// Quiz content for Cours33 — Écriture classique : Fugue et choral

export interface Question { q: string; opts: string[]; a: number; fb: string; }
export interface Cours33Locale { questions: Question[]; }

const questionsFr: Question[] = [
  // ── Choral Bach (20 questions) ─────────────────────────────────────────────

  { q: "Dans un choral à 4 voix de Bach, quelles voix constituent le choral SATB ?", opts: ["Soprano, Alto, Ténor, Basse", "Soprano, Accordéon, Tuba, Baritone", "Soprano, Altiste, Tromboniste, Bassiste", "Sol, Ré, Mi, Si"], a: 0, fb: "SATB signifie Soprano (voix aiguë féminine), Alto (voix grave féminine), Ténor (voix aiguë masculine) et Basse (voix grave masculine). C'est la formation standard du choral classique depuis le Moyen-Âge." },
  { q: "Dans le style Bach, que doit faire la note sensible (7e degré) ?", opts: ["Descendre vers la dominante", "Monter vers la tonique par demi-ton ascendant", "Rester en place", "Sauter vers la médiante"], a: 1, fb: "La sensible (7e degré, ex : Si en Do majeur) DOIT résoudre vers la tonique (Do) par demi-ton ascendant. C'est la règle la plus stricte du style baroquiste — la violer est une faute grave de style." },
  { q: "Comment doit résoudre la septième de dominante dans un choral Bach ?", opts: ["Elle monte vers la fondamentale de la tonique", "Elle descend par mouvement conjoint", "Elle peut aller n'importe où", "Elle saute d'une quinte"], a: 1, fb: "La 7te de dominante (ex : Fa dans G7) DOIT descendre par mouvement conjoint vers la tierce de la tonique (Mi dans CMaj). C'est le geste résolutif fondamental du contrepoint tonal classique." },
  { q: "Qu'est-ce que la 'doublure de fondamentale' dans un choral à 4 voix ?", opts: ["Jouer la fondamentale deux fois de suite", "Donner la fondamentale de l'accord à deux voix différentes", "Doubler le volume de la basse", "Répéter le premier accord"], a: 1, fb: "Doubler la fondamentale signifie que deux voix chantent la même note (la fondamentale de l'accord) à l'octave ou à l'unisson. C'est le choix par défaut pour compléter un accord à 3 sons (triade) sur 4 voix." },
  { q: "Pourquoi les quintes et octaves parallèles sont-elles interdites dans le choral Bach ?", opts: ["Elles sont trop difficiles à chanter", "Elles créent une fusion des voix qui supprime l'indépendance des lignes — le contrepoint exige des voix distinctes", "Elles sont trop aiguës pour les choristes", "Elles créent une dissonance insupportable"], a: 1, fb: "Les quintes et octaves parallèles fusionnent acoustiquement deux voix en une seule — elles perdent leur indépendance. Or le contrepoint à 4 voix exige 4 lignes distinctes et identifiables. Bach peut écrire des quintes parallèles très occasionnellement, mais c'est l'exception, jamais la règle." },
  { q: "Quelle est la méthode d'harmonisation d'un choral en 4 étapes ?", opts: ["1-Mélodie 2-Accords 3-Rythme 4-Dynamique", "1-Identifier tonalité et cadences 2-Placer la basse 3-Compléter alto/ténor 4-Vérifier les règles", "1-Basse 2-Soprano 3-Alto 4-Ténor", "1-Choisir le mode 2-Écrire la mélodie 3-Harmoniser 4-Réviser"], a: 1, fb: "La méthode académique en 4 étapes : 1/ Identifier la tonalité et marquer les points cadentiels ; 2/ Écrire la basse (la fondation harmonique) ; 3/ Compléter alto et ténor en évitant les fautes ; 4/ Vérifier TOUTES les règles (parallèles, doublures, sensible, 7te)." },
  { q: "Dans quel registre se situe la voix de ténor dans un choral SATB ?", opts: ["Clé de sol 2e ligne, octave normale", "Clé de sol 2e ligne, sonnant une octave plus bas (octavia)", "Clé de fa 4e ligne", "Clé d'ut 3e ligne"], a: 1, fb: "Le ténor est noté en clé de sol 2e ligne avec un petit '8' en dessous (ottava bassa) — il sonne une octave plus bas que noté. Dans la partition SATB choral, soprano et alto partagent une portée (valeurs à l'endroit/renversées) et ténor+basse également." },
  { q: "Peut-on faire sauter la basse d'une quinte dans un choral Bach ?", opts: ["Non — la basse doit toujours aller par degrés conjoints", "Oui — les sauts de quinte et quarte à la basse sont permis et courants dans le style Bach", "Seulement en cadence", "Seulement si c'est le premier accord"], a: 1, fb: "Les sauts de quarte et quinte à la basse sont non seulement permis mais caractéristiques du style Bach — ils marquent les changements d'harmonie forts. Les basses par mouvements conjoints sont pour des accords de passage, les basses sautées pour les harmonies structurelles." },
  { q: "Qu'est-ce que la 'sensible' dans la gamme de Do majeur ?", opts: ["Le Do (tonique)", "Le Sol (dominante)", "Le Si (septième degré naturel)", "Le Fa (sous-dominante)"], a: 2, fb: "La sensible est le 7e degré de la gamme — Si en Do majeur. Elle tire son nom de sa 'sensibilité' tonale : elle est à un demi-ton de la tonique (Si → Do) et a donc une forte attraction vers elle. Ne pas confondre avec le sous-sensible (Sib en Do majeur)." },
  { q: "Comment éviter les octaves parallèles entre soprano et basse dans un choral ?", opts: ["Toujours mouvoir les voix dans le même sens", "Utiliser des mouvements contraires ou obliques — si la basse monte, le soprano descend (ou reste)", "Toujours sauter plutôt que d'aller par degrés", "Doubler systématiquement la tierce"], a: 1, fb: "Le mouvement contraire (une voix monte, l'autre descend) est le meilleur moyen d'éviter octaves et quintes parallèles. Si la basse monte d'une quinte, le soprano devrait descendre. Le mouvement oblique (une voix stationnaire) est aussi sûr." },

  { q: "Qu'est-ce qu'un 'choral harmonisé' de Bach ?", opts: ["Un choral composé par Bach", "Une mélodie préexistante (souvent luthérienne) harmonisée à 4 voix par Bach", "Un choral joué à l'orgue solo", "Un choral sans paroles"], a: 1, fb: "Bach n'a pas composé les mélodies de ses choraux — il les a harmonisées. Ces mélodies sont des hymnes luthériens préexistants (souvent du XVIe siècle). Bach a produit ~400 harmonisations SATB de ces mélodies, qui sont considérées comme le sommet du genre." },
  { q: "Comment identifier les 'points de respiration' dans un choral pour placer les cadences ?", opts: ["Aux barres de mesure uniquement", "Aux points, virgules et fins de phrases du texte — la cadence correspond à la ponctuation verbale", "Toutes les 4 mesures", "Uniquement au début et à la fin"], a: 1, fb: "Dans un choral, les points de respiration suivent le texte chanté. Une virgule → cadence demi ou imparfaite (suspension). Un point → cadence parfaite (finale). Bach calque rigoureusement la ponctuation musicale sur la ponctuation verbale — la musique respire comme la phrase." },
  { q: "Quelle est la doublure à éviter absolument dans un accord de dominante (V) ?", opts: ["Doubler la fondamentale", "Doubler la tierce", "Doubler la sensible", "Doubler la quinte"], a: 2, fb: "Doubler la sensible (7e degré) dans l'accord de dominante est une faute grave : les deux sensibles devront toutes les deux monter vers la tonique, créant des octaves parallèles obligatoires. On évite donc de doubler la sensible — on double la fondamentale ou la quinte à la place." },
  { q: "Dans quel contexte Bach autorise-t-il le mouvement de quinte entre basse et ténor ?", opts: ["Jamais", "Dans les cadences authentiques plagales", "Quand le mouvement est contraire ou oblique (quinte directe évitée)", "Uniquement à la soprano"], a: 2, fb: "Les quintes cachées (deux voix atteignent une quinte par mouvement direct) sont à éviter, surtout entre voix extrêmes. En revanche, une quinte en mouvement contraire (l'une monte, l'autre descend) n'est pas parallèle. Bach applique cette règle strictement aux voix extrêmes et avec souplesse aux voix internes." },
  { q: "Comment réaliser un accord de dominante à 4 voix en Do majeur (G7 : Sol–Si–Ré–Fa) ?", opts: ["Sol–Sol–Si–Ré (doubler fondamentale, omettre 7te)", "Sol–Si–Ré–Fa (toutes les notes, aucune doublure)", "Sol–Si–Sol–Ré (doubler fondamentale, omettre 7te)", "Sol–Fa–Ré–Si (renversement)"], a: 1, fb: "G7 contient 4 notes distinctes (Sol–Si–Ré–Fa), donc à 4 voix, on peut écrire toutes les notes sans doublure. C'est même préférable en accord de dominante car la septième (Fa) est cruciale pour la résolution — ne pas l'omettre. Basse : Sol. Soprano : Sol, Si ou Ré selon la mélodie donnée." },

  // ── Fugue (20 questions) ───────────────────────────────────────────────────

  { q: "Qu'est-ce que le 'sujet' d'une fugue ?", opts: ["L'argument littéraire du texte", "Le thème principal, énoncé seul au début à la tonique, sans accompagnement", "La réponse harmonique", "Le contre-sujet"], a: 1, fb: "Le sujet (Subject) est le thème principal de la fugue — généralement 1 à 4 mesures. Il est énoncé seul au début par une voix unique, sans accompagnement, à la tonique. Tout le reste de la fugue est construit sur ce matériau initial." },
  { q: "Quelle est la différence entre 'réponse réelle' et 'réponse tonale' ?", opts: ["La réponse réelle est à la bonne hauteur, la tonale est fausse", "La réponse réelle est une transposition exacte du sujet à la dominante ; la réponse tonale modifie légèrement certains intervalles pour éviter une modulation prématurée", "Elles sont identiques", "La réponse tonale est plus longue"], a: 1, fb: "Réponse réelle : transposition exacte du sujet à la dominante (quinte au-dessus). Réponse tonale : transposition avec modification d'un ou deux intervalles — souvent quand le sujet commence sur la dominante (quinte), le début de la réponse commence sur la tonique pour ancrer la tonalité." },
  { q: "Qu'est-ce que le 'contre-sujet' (Countersubject) ?", opts: ["Un deuxième sujet indépendant", "La mélodie qui accompagne la réponse simultanément — en contrepoint avec le sujet ou la réponse, elle réapparaît à chaque entrée du sujet", "Le sujet joué à l'envers", "La basse du sujet"], a: 1, fb: "Le contre-sujet est le contrepoint écrit pour accompagner la réponse (et le sujet). Il est en contrepoint double avec le sujet : on peut les intervertir (le sujet monte à la voix du contre-sujet et vice versa) sans créer de fautes. Sa constance est la marque d'une fugue bien construite." },
  { q: "Qu'appelle-t-on 'exposition' dans une fugue ?", opts: ["La première section où toutes les voix entrent successivement avec le sujet", "Le développement central", "La conclusion de la fugue", "Le premier épisode"], a: 0, fb: "L'exposition est la section d'ouverture de la fugue où toutes les voix entrent une par une avec le sujet (à la tonique) ou la réponse (à la dominante). Dans une fugue à 4 voix, l'exposition comprend 4 entrées alternant sujet (I) et réponse (V)." },
  { q: "Qu'est-ce qu'un 'épisode' dans une fugue ?", opts: ["Une section où le sujet est absent — musique de liaison entre deux entrées du sujet, souvent séquentielle et modulante", "Une autre exposition", "Le retour du sujet en augmentation", "Le contre-sujet seul"], a: 0, fb: "Un épisode (ou divertissement) est une section de la fugue où le sujet complet n'apparaît pas. On y entend souvent des fragments du sujet ou du contre-sujet en séquences modulantes. Les épisodes servent à lier les entrées du sujet et à moduler vers d'autres tonalités." },
  { q: "Qu'est-ce que la 'strette' ?", opts: ["Le sujet joué deux fois de suite", "Le chevauchement d'entrées du sujet — la 2e voix entre avec le sujet avant que la 1ère voix ait terminé le sien", "Le sujet en augmentation", "La conclusion de la fugue"], a: 1, fb: "La strette est une technique d'intensification : les entrées du sujet se chevauchent, créant une compression temporelle. La 2e voix commence le sujet avant que la 1ère l'ait terminé. La strette est souvent réservée au climax de la fugue pour créer la tension maximale." },
  { q: "Qu'est-ce que 'l'augmentation' d'un sujet de fugue ?", opts: ["Jouer le sujet plus fort", "Jouer le sujet en valeurs doubles — chaque noire devient blanche, chaque croche devient noire", "Transposer le sujet plus haut", "Jouer le sujet dans un autre mode"], a: 1, fb: "L'augmentation (Augmentation) consiste à jouer le sujet en valeurs rythmiques doubles. Si le sujet original est : noire–croche–croche–noire, l'augmentation donne : blanche–noire–noire–blanche. L'effet est de grandir et de solenniser le sujet, souvent utilisé en climax final." },
  { q: "Qu'est-ce que 'l'inversion' d'un sujet de fugue ?", opts: ["Jouer le sujet à l'envers dans le temps", "Retourner le sujet mélodiquement — chaque intervalle montant devient descendant et vice versa", "Jouer le sujet dans le mode opposé", "Jouer le sujet dans une autre voix"], a: 1, fb: "L'inversion mélodique (ou inversion diatonique) retourne le sujet : chaque intervalle monte là où il descendait et vice versa. Si le sujet monte d'une tierce puis descend d'une seconde, l'inversion descend d'une tierce puis monte d'une seconde. C'est une technique du contrepoint double." },
  { q: "Combien de voix a généralement une fugue de Bach dans le Clavier Bien Tempéré ?", opts: ["Toujours 4 voix", "2 à 5 voix selon la fugue, le plus souvent 3 ou 4", "Toujours 2 voix", "6 voix en standard"], a: 1, fb: "Les fugues du Clavier Bien Tempéré varient entre 2 et 5 voix. La plupart sont à 3 voix (souplesse pianistique) ou 4 voix (richesse contrapuntique). La fugue à 5 voix est rare et réservée à des moments de grandeur solennelle. Il n'y a pas de norme fixe — Bach choisit selon l'expression recherchée." },
  { q: "Qu'est-ce que le 'Clavier Bien Tempéré' de Bach ?", opts: ["Un traité d'accordage des pianos", "Un recueil de 48 préludes et fugues (deux volumes de 24 paires) dans les 24 tonalités majeures et mineures — chef-d'œuvre du contrepoint tonal", "Un opéra en 48 actes", "Une méthode de piano pour débutants"], a: 1, fb: "Le Clavier Bien Tempéré (Das Wohltemperierte Klavier) comprend deux recueils de 24 préludes et fugues chacun, couvrant toutes les tonalités majeures et mineures. Bach l'a composé pour démontrer la praticabilité du tempérament égal et pour enseigner le contrepoint. C'est la 'bible' du pianiste classique." },
  { q: "Qu'est-ce que 'L'Art de la Fugue' BWV 1080 ?", opts: ["Un opéra de Bach", "Le testament fugal de Bach — 14 fugues (Contrapuncti) et 4 canons sur un seul sujet chromatique, inachevé au moment de sa mort", "Une collection de 48 choraux", "Un concerto pour orgue"], a: 1, fb: "L'Art de la Fugue est l'œuvre testament de Bach, composée dans ses dernières années. Tous les Contrapuncti (fugues) sont basés sur le même sujet : Ré–La–Fa–Ré en Do mineur. L'œuvre s'interrompt au milieu d'une fugue qui introduit le motif B-A-C-H (Sib–La–Do–Si) — Bach ne put jamais la terminer." },
  { q: "Comment identifier le sujet dans l'exposition d'une fugue à l'écoute ?", opts: ["C'est toujours la voix la plus grave", "C'est la première mélodie présentée seule sans accompagnement, dans n'importe quelle voix", "C'est le motif le plus répété", "C'est la ligne de basse"], a: 1, fb: "Dans l'exposition, la première voix qui entre (quelle que soit sa tessiture) présente le sujet seul, sans aucun accompagnement. C'est la seule mélodie qu'on entend. Puis la 2e voix entre avec la réponse (pendant que la 1ère continue avec le contre-sujet). Identifier l'entrée solitaire initiale = identifier le sujet." },
  { q: "Dans une fugue à 4 voix, quel est l'ordre typique des entrées dans l'exposition ?", opts: ["Toujours soprano → alto → ténor → basse", "Variable — souvent aigu→grave ou grave→aigu, alternant tonique et dominante : S-A-T-B ou B-T-A-S", "Toujours les voix par paires simultanées", "Toujours basse en premier"], a: 1, fb: "L'ordre des entrées dans l'exposition varie selon la fugue. Bach alterne souvent entre voix aiguës et graves (S-B-A-T ou B-S-T-A) pour créer de la variété. L'ordre tonique-dominante alterne : voix 1 (sujet, tonique), voix 2 (réponse, dominante), voix 3 (sujet, tonique), voix 4 (réponse, dominante)." },
  { q: "Qu'est-ce que le 'codetta' dans l'exposition d'une fugue ?", opts: ["La conclusion de la fugue", "Un court passage de transition entre les entrées de l'exposition, permettant de moduler brièvement vers la dominante avant l'entrée de la réponse", "Le contre-sujet final", "La strette finale"], a: 1, fb: "La codetta est un bref passage interstitiel dans l'exposition, entre la fin du sujet et le début de la réponse. Elle permet une transition harmonique douce (généralement vers la dominante) avant que la 2e voix entre. Pas toutes les fugues ont une codetta — certaines ont des entrées directes sans transition." },
  { q: "Comment la fugue se termine-t-elle généralement ?", opts: ["Par une cadence plagale uniquement", "Par une cadence parfaite (V→I) avec parfois une pédale de tonique finale, souvent un accord avec tierce picarde en mode mineur", "Par une répétition du sujet au début", "Par un silence"], a: 1, fb: "La fugue se termine généralement par une cadence parfaite forte (V→I). En mode mineur, Bach finit souvent avec la 'tierce picarde' (Do# en Do mineur → accord de Do majeur). Une pédale de tonique à la basse peut soutenir les dernières mesures, créant une stabilité finale après toute la tension contrapuntique." },

  { q: "Qu'est-ce que le 'rétrograde' d'un sujet de fugue ?", opts: ["Le sujet joué avec le rythme inversé", "Le sujet joué à reculons — de la dernière note à la première", "Le sujet transposé à la quinte inférieure", "Le sujet fragmenté en motifs courts"], a: 1, fb: "Le rétrograde (ou cancrizans) consiste à jouer le sujet de la dernière note à la première. Si le sujet est Do–Ré–Mib–Fa, le rétrograde est Fa–Mib–Ré–Do. C'est une technique de contrepoint canonique, très utilisée dans L'Art de la Fugue. Combiné à l'inversion, on obtient le rétrograde inversé." },
  { q: "Qu'appelle-t-on 'contrepoint double' ou 'contrepoint inversable' ?", opts: ["Un contrepoint à deux sujets différents", "Un contrepoint où les deux lignes peuvent être interverties (l'une passe au grave, l'autre à l'aigu) sans créer de fautes de contrepoint", "Un contrepoint en mode mineur", "Un contrepoint à l'octave"], a: 1, fb: "Le contrepoint double (ou inversable) permet d'intervertir les voix : la voix supérieure passe en voix inférieure et vice versa. Pour que cela fonctionne, les intervalles entre les voix doivent rester consonants dans les deux arrangements. C'est la condition pour qu'un contre-sujet soit 'parfaitement' construit." },
  { q: "Dans 'L'Art de la Fugue', quel est le sujet qui parcourt toutes les fugues ?", opts: ["Sol–Sol–Sol–Mib (comme Beethoven)", "Ré–La–Fa–Ré en Do mineur (le sujet unifié de toute l'œuvre)", "Do–Ré–Mi–Fa (gamme ascendante)", "Mi–Fa–Ré–Sol (motif de 4 notes)"], a: 1, fb: "Le sujet unifié de L'Art de la Fugue est Ré–La–Fa–Ré en Do mineur. Toutes les 14 fugues (Contrapuncti) et les 4 canons sont des développements contrapuntiques de ce même sujet. L'œuvre démontre l'exhaustivité des possibilités fugales d'un seul matériau thématique." },
  { q: "Qu'est-ce qu'un 'canon' en contrepoint, proche de la fugue ?", opts: ["Une pièce pour instruments en cuivre uniquement", "Une imitation stricte et continue — la voix 2 suit la voix 1 avec exactement les mêmes notes décalées dans le temps, indéfiniment", "Un accord répété", "Une séquence chromatique"], a: 1, fb: "Un canon est une imitation stricte et continue : la voix 2 reprend exactement ce que vient de jouer la voix 1 (ou à la quinte, ou en inversion...). Contrairement à la fugue, l'imitation du canon est totale et permanente. Les exemples célèbres : Canon de Pachelbel, Row Your Boat, Frère Jacques en canon." },
  { q: "Quand dit-on qu'une fugue utilise un 'sujet tonal' plutôt qu'un 'sujet réel' ?", opts: ["Quand le sujet module vers une autre tonalité", "Quand le sujet commence sur la dominante — la réponse commencera alors sur la tonique pour préserver la centralité tonale", "Quand le sujet n'a pas de contre-sujet", "Quand le sujet est chromatique"], a: 1, fb: "Un sujet qui s'ouvre sur la dominante (Sol en Do majeur) reçoit une 'réponse tonale' plutôt que réelle : la réponse commence sur la tonique (Do) au lieu de la dominante (Ré). Cette modification maintient la stabilité de Do comme centre et évite que la réponse semble moduler prématurément vers Sol majeur." },
];

const questionsEn: Question[] = [
  { q: "In a 4-voice Bach chorale, which voices make up the SATB chorale?", opts: ["Soprano, Alto, Tenor, Bass", "Soprano, Accordion, Tuba, Baritone", "Soprano, Violist, Trombonist, Bassist", "G, D, E, B"], a: 0, fb: "SATB stands for Soprano (high female voice), Alto (low female voice), Tenor (high male voice) and Bass (low male voice). It has been the standard formation for the classical chorale since the Middle Ages." },
  { q: "In Bach's style, what must the leading tone (7th degree) do?", opts: ["Descend to the dominant", "Rise to the tonic by ascending semitone", "Stay in place", "Leap to the mediant"], a: 1, fb: "The leading tone (7th degree, e.g. B in C major) MUST resolve to the tonic (C) by ascending semitone. This is the strictest rule of Baroque style — violating it is a serious stylistic error." },
  { q: "How must the dominant seventh resolve in a Bach chorale?", opts: ["It rises to the root of the tonic", "It descends by stepwise motion", "It can go anywhere", "It leaps a fifth"], a: 1, fb: "The dominant seventh (e.g. F in G7) MUST descend by step to the third of the tonic (E in CMaj). This is the fundamental resolving gesture of classical tonal counterpoint." },
  { q: "What is 'root doubling' in a 4-voice chorale?", opts: ["Playing the root twice in a row", "Giving the root of the chord to two different voices", "Doubling the volume of the bass", "Repeating the first chord"], a: 1, fb: "Doubling the root means two voices sing the same note (the root of the chord) at the octave or unison. It is the default choice for completing a 3-note chord (triad) across 4 voices." },
  { q: "Why are parallel fifths and octaves forbidden in Bach chorales?", opts: ["They are too difficult to sing", "They create a fusion of voices that removes the independence of lines — counterpoint requires distinct voices", "They are too high for choristers", "They create an unbearable dissonance"], a: 1, fb: "Parallel fifths and octaves acoustically merge two voices into one — they lose their independence. Yet 4-voice counterpoint requires 4 distinct and identifiable lines. Bach can write parallel fifths very occasionally, but it is an exception, never the rule." },
  { q: "What is the 4-step method for harmonizing a chorale?", opts: ["1-Melody 2-Chords 3-Rhythm 4-Dynamics", "1-Identify key and cadences 2-Place the bass 3-Complete alto/tenor 4-Check the rules", "1-Bass 2-Soprano 3-Alto 4-Tenor", "1-Choose the mode 2-Write the melody 3-Harmonize 4-Revise"], a: 1, fb: "The academic 4-step method: 1/ Identify the key and mark cadential points; 2/ Write the bass (the harmonic foundation); 3/ Complete alto and tenor while avoiding errors; 4/ Check ALL rules (parallels, doublings, leading tone, 7th)." },
  { q: "In which register does the tenor voice sit in an SATB chorale?", opts: ["Treble clef, normal octave", "Treble clef, sounding one octave lower (ottava bassa)", "Bass clef 4th line", "Alto clef 3rd line"], a: 1, fb: "The tenor is notated in treble clef with a small '8' below (ottava bassa) — it sounds one octave lower than written. In the SATB choral score, soprano and alto share one staff (stems up/down) and tenor + bass share another." },
  { q: "Can the bass leap a fifth in a Bach chorale?", opts: ["No — the bass must always move by step", "Yes — fifth and fourth leaps in the bass are permitted and common in Bach's style", "Only in a cadence", "Only if it is the first chord"], a: 1, fb: "Fourth and fifth leaps in the bass are not only permitted but characteristic of Bach's style — they mark strong harmonic changes. Stepwise bass motion is for passing chords; leaping basses mark structural harmonies." },
  { q: "What is the 'leading tone' in the C major scale?", opts: ["C (tonic)", "G (dominant)", "B (seventh degree naturally)", "F (subdominant)"], a: 2, fb: "The leading tone is the 7th degree of the scale — B in C major. It gets its name from its tonal 'sensitivity': it is a semitone away from the tonic (B → C) and therefore has a strong attraction toward it. Do not confuse it with the subtonic (Bb in C major)." },
  { q: "How can parallel octaves between soprano and bass be avoided in a chorale?", opts: ["Always move the voices in the same direction", "Use contrary or oblique motion — if the bass goes up, the soprano goes down (or stays)", "Always leap rather than step", "Systematically double the third"], a: 1, fb: "Contrary motion (one voice rises, the other descends) is the best way to avoid parallel octaves and fifths. If the bass rises a fifth, the soprano should descend. Oblique motion (one voice stationary) is also safe." },
  { q: "What is a 'harmonized chorale' by Bach?", opts: ["A chorale composed by Bach", "A pre-existing melody (often Lutheran) harmonized in 4 voices by Bach", "A chorale played on solo organ", "A chorale without words"], a: 1, fb: "Bach did not compose the melodies of his chorales — he harmonized them. These melodies are pre-existing Lutheran hymns (often from the 16th century). Bach produced ~400 SATB harmonizations of these melodies, considered the pinnacle of the genre." },
  { q: "How to identify 'breathing points' in a chorale to place cadences?", opts: ["At bar lines only", "At periods, commas and phrase ends in the text — the cadence corresponds to verbal punctuation", "Every 4 bars", "Only at the beginning and end"], a: 1, fb: "In a chorale, breathing points follow the sung text. A comma → half or imperfect cadence (suspension). A period → perfect cadence (final). Bach rigorously maps musical punctuation onto verbal punctuation — the music breathes like the sentence." },
  { q: "What doubling must absolutely be avoided in a dominant chord (V)?", opts: ["Doubling the root", "Doubling the third", "Doubling the leading tone", "Doubling the fifth"], a: 2, fb: "Doubling the leading tone (7th degree) in the dominant chord is a serious error: both leading tones must rise to the tonic, creating obligatory parallel octaves. Therefore avoid doubling the leading tone — double the root or fifth instead." },
  { q: "In what context does Bach allow the fifth motion between bass and tenor?", opts: ["Never", "In authentic plagal cadences", "When the motion is contrary or oblique (direct fifths avoided)", "Only in the soprano"], a: 2, fb: "Hidden fifths (two voices reaching a fifth by direct motion) are to be avoided, especially between outer voices. However, a fifth in contrary motion (one rises, the other descends) is not parallel. Bach applies this rule strictly to outer voices and more flexibly to inner voices." },
  { q: "How to realize a 4-voice dominant chord in C major (G7: G–B–D–F)?", opts: ["G–G–B–D (double root, omit 7th)", "G–B–D–F (all notes, no doubling)", "G–B–G–D (double root, omit 7th)", "G–F–D–B (inversion)"], a: 1, fb: "G7 contains 4 distinct notes (G–B–D–F), so in 4 voices all notes can be written without doubling. This is even preferable for a dominant chord since the seventh (F) is crucial for the resolution — do not omit it. Bass: G. Soprano: G, B, or D depending on the given melody." },
  { q: "What is the 'subject' of a fugue?", opts: ["The literary argument of a text", "The main theme, stated alone at the beginning in the tonic, without accompaniment", "The harmonic answer", "The countersubject"], a: 1, fb: "The subject is the main theme of the fugue — generally 1 to 4 bars. It is stated alone at the beginning by a single voice, without accompaniment, in the tonic. Everything else in the fugue is built on this initial material." },
  { q: "What is the difference between a 'real answer' and a 'tonal answer'?", opts: ["The real answer is at the correct pitch, the tonal one is wrong", "The real answer is an exact transposition of the subject to the dominant; the tonal answer slightly modifies certain intervals to avoid premature modulation", "They are identical", "The tonal answer is longer"], a: 1, fb: "Real answer: exact transposition of the subject to the dominant (a fifth above). Tonal answer: transposition with modification of one or two intervals — often when the subject begins on the dominant (fifth), the start of the answer begins on the tonic to anchor the key." },
  { q: "What is the 'countersubject'?", opts: ["A second independent subject", "The melody that accompanies the answer simultaneously — in counterpoint with the subject or answer, it reappears at each entry of the subject", "The subject played in reverse", "The bass of the subject"], a: 1, fb: "The countersubject is the counterpoint written to accompany the answer (and subject). It is in double counterpoint with the subject: they can be inverted (the subject moves to the countersubject's voice and vice versa) without creating errors. Its consistency is the mark of a well-constructed fugue." },
  { q: "What is called the 'exposition' in a fugue?", opts: ["The opening section where all voices enter successively with the subject", "The central development", "The conclusion of the fugue", "The first episode"], a: 0, fb: "The exposition is the opening section of the fugue where all voices enter one by one with the subject (in the tonic) or the answer (in the dominant). In a 4-voice fugue, the exposition comprises 4 entries alternating subject (I) and answer (V)." },
  { q: "What is an 'episode' in a fugue?", opts: ["A section where the subject is absent — transitional music between two subject entries, often sequential and modulating", "Another exposition", "The return of the subject in augmentation", "The countersubject alone"], a: 0, fb: "An episode (or divertimento) is a section of the fugue where the complete subject does not appear. Fragments of the subject or countersubject in modulating sequences are often heard. Episodes serve to link subject entries and modulate to other keys." },
  { q: "What is 'stretto'?", opts: ["The subject played twice in a row", "The overlapping of subject entries — the 2nd voice enters with the subject before the 1st voice has finished theirs", "The subject in augmentation", "The conclusion of the fugue"], a: 1, fb: "Stretto is an intensification technique: subject entries overlap, creating temporal compression. The 2nd voice begins the subject before the 1st has finished it. Stretto is often reserved for the fugue's climax to create maximum tension." },
  { q: "What is 'augmentation' of a fugue subject?", opts: ["Playing the subject louder", "Playing the subject in double note values — each quarter note becomes a half, each eighth becomes a quarter", "Transposing the subject higher", "Playing the subject in another mode"], a: 1, fb: "Augmentation consists of playing the subject in doubled rhythmic values. If the original subject is: quarter–eighth–eighth–quarter, augmentation gives: half–quarter–quarter–half. The effect is to enlarge and solemnize the subject, often used at the final climax." },
  { q: "What is 'inversion' of a fugue subject?", opts: ["Playing the subject backwards in time", "Turning the subject melodically upside down — each ascending interval becomes descending and vice versa", "Playing the subject in the opposite mode", "Playing the subject in another voice"], a: 1, fb: "Melodic inversion turns the subject upside down: each interval goes up where it went down and vice versa. If the subject rises a third then descends a second, the inversion descends a third then rises a second. It is a double counterpoint technique." },
  { q: "How many voices does a Bach fugue from the Well-Tempered Clavier generally have?", opts: ["Always 4 voices", "2 to 5 voices depending on the fugue, most often 3 or 4", "Always 2 voices", "6 voices as standard"], a: 1, fb: "The fugues of the Well-Tempered Clavier range from 2 to 5 voices. Most are in 3 voices (pianistic flexibility) or 4 voices (contrapuntal richness). The 5-voice fugue is rare and reserved for moments of solemn grandeur. There is no fixed standard — Bach chooses according to the desired expression." },
  { q: "What is Bach's 'Well-Tempered Clavier'?", opts: ["A treatise on piano tuning", "A collection of 48 preludes and fugues (two volumes of 24 pairs) in all 24 major and minor keys — a masterpiece of tonal counterpoint", "An opera in 48 acts", "A piano method for beginners"], a: 1, fb: "The Well-Tempered Clavier (Das Wohltemperierte Klavier) comprises two collections of 24 preludes and fugues each, covering all major and minor keys. Bach composed it to demonstrate the practicability of equal temperament and to teach counterpoint. It is the classical pianist's 'bible'." },
  { q: "What is 'The Art of Fugue' BWV 1080?", opts: ["A Bach opera", "Bach's fugal testament — 14 fugues (Contrapuncti) and 4 canons on a single chromatic subject, left unfinished at his death", "A collection of 48 chorales", "A concerto for organ"], a: 1, fb: "The Art of Fugue is Bach's testament work, composed in his final years. All Contrapuncti (fugues) are based on the same subject: D–A–F–D in C minor. The work breaks off mid-fugue when the motif B–A–C–H (Bb–A–C–B) is introduced — Bach was unable to finish it." },
  { q: "How to identify the subject in the exposition of a fugue by ear?", opts: ["It is always the lowest voice", "It is the first melody presented alone without accompaniment, in any voice", "It is the most repeated motif", "It is the bass line"], a: 1, fb: "In the exposition, the first voice to enter (regardless of its register) presents the subject alone, without any accompaniment. It is the only melody one hears. Then the 2nd voice enters with the answer (while the 1st continues with the countersubject). Identifying the initial solitary entry = identifying the subject." },
  { q: "In a 4-voice fugue, what is the typical order of entries in the exposition?", opts: ["Always soprano → alto → tenor → bass", "Variable — often high→low or low→high, alternating tonic and dominant: S-A-T-B or B-T-A-S", "Always in simultaneous pairs", "Always bass first"], a: 1, fb: "The order of entries in the exposition varies by fugue. Bach often alternates between high and low voices (S-B-A-T or B-S-T-A) to create variety. The tonic-dominant order alternates: voice 1 (subject, tonic), voice 2 (answer, dominant), voice 3 (subject, tonic), voice 4 (answer, dominant)." },
  { q: "What is the 'codetta' in the exposition of a fugue?", opts: ["The conclusion of the fugue", "A short transitional passage between entries in the exposition, allowing a brief modulation to the dominant before the answer's entry", "The final countersubject", "The final stretto"], a: 1, fb: "The codetta is a brief interstitial passage in the exposition, between the end of the subject and the start of the answer. It allows a smooth harmonic transition (generally to the dominant) before the 2nd voice enters. Not all fugues have a codetta — some have direct entries without transition." },
  { q: "How does a fugue generally end?", opts: ["With a plagal cadence only", "With a perfect cadence (V→I) with sometimes a final tonic pedal, often a chord with Picardy third in minor mode", "With a repetition of the subject at the beginning", "With silence"], a: 1, fb: "The fugue generally ends with a strong perfect cadence (V→I). In minor mode, Bach often finishes with the 'Picardy third' (C# in C minor → C major chord). A tonic pedal in the bass may support the final bars, creating final stability after all the contrapuntal tension." },
  { q: "What is the 'retrograde' of a fugue subject?", opts: ["The subject played with the rhythm inverted", "The subject played backwards — from the last note to the first", "The subject transposed a fifth lower", "The subject fragmented into short motifs"], a: 1, fb: "The retrograde (or cancrizans) consists of playing the subject from the last note to the first. If the subject is C–D–Eb–F, the retrograde is F–Eb–D–C. It is a canonical counterpoint technique, widely used in The Art of Fugue. Combined with inversion, one gets the retrograde inversion." },
  { q: "What is called 'double counterpoint' or 'invertible counterpoint'?", opts: ["A counterpoint with two different subjects", "A counterpoint where the two lines can be swapped (one moves to the low voice, the other to the high) without creating counterpoint errors", "A counterpoint in minor mode", "A counterpoint at the octave"], a: 1, fb: "Double (or invertible) counterpoint allows the voices to be swapped: the upper voice moves to the lower position and vice versa. For this to work, the intervals between the voices must remain consonant in both arrangements. This is the condition for a countersubject to be 'perfectly' constructed." },
  { q: "In 'The Art of Fugue', what is the subject that runs through all the fugues?", opts: ["G–G–G–Eb (like Beethoven)", "D–A–F–D in C minor (the unified subject of the entire work)", "C–D–E–F (ascending scale)", "E–F–D–G (4-note motif)"], a: 1, fb: "The unified subject of The Art of Fugue is D–A–F–D in C minor. All 14 fugues (Contrapuncti) and 4 canons are contrapuntal developments of this same subject. The work demonstrates the exhaustiveness of fugal possibilities from a single thematic material." },
  { q: "What is a 'canon' in counterpoint, close to the fugue?", opts: ["A piece for brass instruments only", "Strict and continuous imitation — voice 2 follows voice 1 with exactly the same notes offset in time, indefinitely", "A repeated chord", "A chromatic sequence"], a: 1, fb: "A canon is strict and continuous imitation: voice 2 takes up exactly what voice 1 just played (or at the fifth, or in inversion...). Unlike the fugue, canonic imitation is total and permanent. Famous examples: Pachelbel's Canon, Row Your Boat, Frère Jacques in canon." },
  { q: "When is a fugue said to use a 'tonal subject' rather than a 'real subject'?", opts: ["When the subject modulates to another key", "When the subject begins on the dominant — the answer will then begin on the tonic to preserve tonal centrality", "When the subject has no countersubject", "When the subject is chromatic"], a: 1, fb: "A subject that opens on the dominant (G in C major) receives a 'tonal answer' rather than a real one: the answer begins on the tonic (C) instead of the dominant (D). This modification maintains C as the center and prevents the answer from seeming to modulate prematurely to G major." },
];

const questionsEs: Question[] = [
  { q: "En un coral Bach a 4 voces, ¿qué voces forman el coral SATB?", opts: ["Soprano, Alto, Tenor, Bajo", "Soprano, Acordeón, Tuba, Barítono", "Soprano, Viola, Trombón, Contrabajo", "Sol, Re, Mi, Si"], a: 0, fb: "SATB significa Soprano (voz femenina aguda), Alto (voz femenina grave), Tenor (voz masculina aguda) y Bajo (voz masculina grave). Es la formación estándar del coral clásico desde la Edad Media." },
  { q: "En el estilo Bach, ¿qué debe hacer la nota sensible (7.° grado)?", opts: ["Descender hacia la dominante", "Subir hacia la tónica por semitono ascendente", "Quedarse en su lugar", "Saltar hacia la mediante"], a: 1, fb: "La sensible (7.° grado, ej.: Si en Do mayor) DEBE resolver hacia la tónica (Do) por semitono ascendente. Es la regla más estricta del estilo barroco — violarlo es una falta grave de estilo." },
  { q: "¿Cómo debe resolver la séptima de dominante en un coral Bach?", opts: ["Sube hacia la fundamental de la tónica", "Desciende por movimiento conjunto", "Puede ir a cualquier parte", "Salta una quinta"], a: 1, fb: "La 7ª de dominante (ej.: Fa en G7) DEBE descender por grado conjunto hacia la tercera de la tónica (Mi en Do Mayor). Es el gesto resolutivo fundamental del contrapunto tonal clásico." },
  { q: "¿Qué es el 'doblamiento de la fundamental' en un coral a 4 voces?", opts: ["Tocar la fundamental dos veces seguidas", "Dar la fundamental del acorde a dos voces diferentes", "Doblar el volumen del bajo", "Repetir el primer acorde"], a: 1, fb: "Doblar la fundamental significa que dos voces cantan la misma nota (la fundamental del acorde) a la octava o al unísono. Es la elección por defecto para completar un acorde de 3 sonidos (tríada) en 4 voces." },
  { q: "¿Por qué se prohíben las quintas y octavas paralelas en el coral Bach?", opts: ["Son demasiado difíciles de cantar", "Crean una fusión de voces que suprime la independencia de las líneas — el contrapunto exige voces distintas", "Son demasiado agudas para los coristas", "Crean una disonancia insoportable"], a: 1, fb: "Las quintas y octavas paralelas fusionan acústicamente dos voces en una sola — pierden su independencia. Sin embargo, el contrapunto a 4 voces exige 4 líneas distintas e identificables. Bach puede escribir quintas paralelas muy ocasionalmente, pero es la excepción, nunca la regla." },
  { q: "¿Cuál es el método de armonización de un coral en 4 pasos?", opts: ["1-Melodía 2-Acordes 3-Ritmo 4-Dinámica", "1-Identificar tonalidad y cadencias 2-Colocar el bajo 3-Completar alto/tenor 4-Verificar las reglas", "1-Bajo 2-Soprano 3-Alto 4-Tenor", "1-Elegir el modo 2-Escribir la melodía 3-Armonizar 4-Revisar"], a: 1, fb: "El método académico en 4 pasos: 1/ Identificar la tonalidad y marcar los puntos cadenciales; 2/ Escribir el bajo (la fundación armónica); 3/ Completar alto y tenor evitando faltas; 4/ Verificar TODAS las reglas (paralelas, doblamientos, sensible, 7ª)." },
  { q: "¿En qué registro se sitúa la voz de tenor en un coral SATB?", opts: ["Clave de sol 2ª línea, octava normal", "Clave de sol 2ª línea, sonando una octava más bajo (ottava bassa)", "Clave de fa 4ª línea", "Clave de do 3ª línea"], a: 1, fb: "El tenor se escribe en clave de sol con un pequeño '8' debajo (ottava bassa) — suena una octava más bajo que lo escrito. En la partitura SATB coral, soprano y alto comparten un pentagrama (plicas arriba/abajo) y tenor+bajo igualmente." },
  { q: "¿Puede el bajo saltar una quinta en un coral Bach?", opts: ["No — el bajo debe ir siempre por grados conjuntos", "Sí — los saltos de quinta y cuarta en el bajo están permitidos y son frecuentes en el estilo Bach", "Solo en cadencia", "Solo si es el primer acorde"], a: 1, fb: "Los saltos de cuarta y quinta en el bajo no solo están permitidos sino que son característicos del estilo Bach — marcan los cambios armónicos fuertes. Los bajos por movimientos conjuntos son para acordes de paso, los bajos saltados para las armonías estructurales." },
  { q: "¿Qué es la 'sensible' en la escala de Do mayor?", opts: ["El Do (tónica)", "El Sol (dominante)", "El Si (séptimo grado natural)", "El Fa (subdominante)"], a: 2, fb: "La sensible es el 7.° grado de la escala — Si en Do mayor. Debe su nombre a su 'sensibilidad' tonal: está a un semitono de la tónica (Si → Do) y tiene una fuerte atracción hacia ella. No confundir con el subtónico (Sib en Do mayor)." },
  { q: "¿Cómo evitar las octavas paralelas entre soprano y bajo en un coral?", opts: ["Siempre mover las voces en el mismo sentido", "Usar movimientos contrarios u oblicuos — si el bajo sube, la soprano baja (o se queda)", "Siempre saltar en lugar de ir por grados", "Doblar sistemáticamente la tercera"], a: 1, fb: "El movimiento contrario (una voz sube, la otra baja) es la mejor manera de evitar octavas y quintas paralelas. Si el bajo sube una quinta, la soprano debería bajar. El movimiento oblicuo (una voz estacionaria) también es seguro." },
  { q: "¿Qué es un 'coral armonizado' de Bach?", opts: ["Un coral compuesto por Bach", "Una melodía preexistente (a menudo luterana) armonizada a 4 voces por Bach", "Un coral tocado en órgano solo", "Un coral sin palabras"], a: 1, fb: "Bach no compuso las melodías de sus corales — las armonizó. Estas melodías son himnos luteranos preexistentes (a menudo del siglo XVI). Bach produjo ~400 armonizaciones SATB de estas melodías, consideradas la cima del género." },
  { q: "¿Cómo identificar los 'puntos de respiración' en un coral para colocar las cadencias?", opts: ["En las barras de compás únicamente", "En los puntos, comas y finales de frase del texto — la cadencia corresponde a la puntuación verbal", "Cada 4 compases", "Solo al principio y al final"], a: 1, fb: "En un coral, los puntos de respiración siguen el texto cantado. Una coma → cadencia a la dominante o imperfecta (suspensión). Un punto → cadencia perfecta (final). Bach sincroniza rigurosamente la puntuación musical con la puntuación verbal — la música respira como la frase." },
  { q: "¿Qué doblamiento debe evitarse absolutamente en un acorde de dominante (V)?", opts: ["Doblar la fundamental", "Doblar la tercera", "Doblar la sensible", "Doblar la quinta"], a: 2, fb: "Doblar la sensible (7.° grado) en el acorde de dominante es una falta grave: ambas sensibles deberán subir hacia la tónica, creando octavas paralelas obligatorias. Por tanto, se evita doblar la sensible — se dobla la fundamental o la quinta en su lugar." },
  { q: "¿En qué contexto Bach permite el movimiento de quinta entre bajo y tenor?", opts: ["Nunca", "En las cadencias auténticas plagales", "Cuando el movimiento es contrario u oblicuo (quintas directas evitadas)", "Solo en la soprano"], a: 2, fb: "Las quintas ocultas (dos voces llegan a una quinta por movimiento directo) deben evitarse, especialmente entre voces externas. En cambio, una quinta en movimiento contrario (una sube, la otra baja) no es paralela. Bach aplica esta regla estrictamente a las voces externas y con flexibilidad a las internas." },
  { q: "¿Cómo realizar un acorde de dominante a 4 voces en Do mayor (G7: Sol–Si–Re–Fa)?", opts: ["Sol–Sol–Si–Re (doblar fundamental, omitir 7ª)", "Sol–Si–Re–Fa (todas las notas, sin doblamiento)", "Sol–Si–Sol–Re (doblar fundamental, omitir 7ª)", "Sol–Fa–Re–Si (inversión)"], a: 1, fb: "G7 contiene 4 notas distintas (Sol–Si–Re–Fa), por tanto a 4 voces se pueden escribir todas las notas sin doblamiento. Esto es incluso preferible en el acorde de dominante ya que la séptima (Fa) es crucial para la resolución — no omitirla. Bajo: Sol. Soprano: Sol, Si o Re según la melodía dada." },
  { q: "¿Qué es el 'sujeto' de una fuga?", opts: ["El argumento literario del texto", "El tema principal, enunciado solo al principio en la tónica, sin acompañamiento", "La respuesta armónica", "El contrasujeto"], a: 1, fb: "El sujeto es el tema principal de la fuga — generalmente 1 a 4 compases. Es enunciado solo al principio por una sola voz, sin acompañamiento, en la tónica. Todo lo demás de la fuga está construido sobre este material inicial." },
  { q: "¿Cuál es la diferencia entre 'respuesta real' y 'respuesta tonal'?", opts: ["La respuesta real está en el tono correcto, la tonal es incorrecta", "La respuesta real es una transposición exacta del sujeto a la dominante; la respuesta tonal modifica ligeramente ciertos intervalos para evitar una modulación prematura", "Son idénticas", "La respuesta tonal es más larga"], a: 1, fb: "Respuesta real: transposición exacta del sujeto a la dominante (quinta superior). Respuesta tonal: transposición con modificación de uno o dos intervalos — a menudo cuando el sujeto comienza en la dominante (quinta), el inicio de la respuesta comienza en la tónica para anclar la tonalidad." },
  { q: "¿Qué es el 'contrasujeto'?", opts: ["Un segundo sujeto independiente", "La melodía que acompaña la respuesta simultáneamente — en contrapunto con el sujeto o la respuesta, reaparece en cada entrada del sujeto", "El sujeto tocado al revés", "El bajo del sujeto"], a: 1, fb: "El contrasujeto es el contrapunto escrito para acompañar la respuesta (y el sujeto). Está en contrapunto doble con el sujeto: pueden intercambiarse (el sujeto pasa a la voz del contrasujeto y viceversa) sin crear faltas. Su constancia es la marca de una fuga bien construida." },
  { q: "¿Qué se llama 'exposición' en una fuga?", opts: ["La primera sección donde todas las voces entran sucesivamente con el sujeto", "El desarrollo central", "La conclusión de la fuga", "El primer episodio"], a: 0, fb: "La exposición es la sección de apertura de la fuga donde todas las voces entran una a una con el sujeto (en la tónica) o la respuesta (en la dominante). En una fuga a 4 voces, la exposición comprende 4 entradas alternando sujeto (I) y respuesta (V)." },
  { q: "¿Qué es un 'episodio' en una fuga?", opts: ["Una sección donde el sujeto está ausente — música de enlace entre dos entradas del sujeto, a menudo secuencial y modulante", "Otra exposición", "El retorno del sujeto en aumentación", "El contrasujeto solo"], a: 0, fb: "Un episodio (o divertimento) es una sección de la fuga donde el sujeto completo no aparece. A menudo se escuchan fragmentos del sujeto o del contrasujeto en secuencias modulantes. Los episodios sirven para enlazar las entradas del sujeto y modular hacia otras tonalidades." },
  { q: "¿Qué es la 'estrecha' (stretto)?", opts: ["El sujeto tocado dos veces seguidas", "El solapamiento de entradas del sujeto — la 2ª voz entra con el sujeto antes de que la 1ª voz haya terminado el suyo", "El sujeto en aumentación", "La conclusión de la fuga"], a: 1, fb: "La estrecha es una técnica de intensificación: las entradas del sujeto se solapan, creando una compresión temporal. La 2ª voz comienza el sujeto antes de que la 1ª lo haya terminado. La estrecha se reserva a menudo para el clímax de la fuga para crear la máxima tensión." },
  { q: "¿Qué es la 'aumentación' de un sujeto de fuga?", opts: ["Tocar el sujeto más fuerte", "Tocar el sujeto en valores dobles — cada negra se convierte en blanca, cada corchea en negra", "Transportar el sujeto más arriba", "Tocar el sujeto en otro modo"], a: 1, fb: "La aumentación consiste en tocar el sujeto en valores rítmicos dobles. Si el sujeto original es: negra–corchea–corchea–negra, la aumentación da: blanca–negra–negra–blanca. El efecto es agrandar y solemnizar el sujeto, usado frecuentemente en el clímax final." },
  { q: "¿Qué es la 'inversión' de un sujeto de fuga?", opts: ["Tocar el sujeto al revés en el tiempo", "Voltear el sujeto melódicamente — cada intervalo ascendente se convierte en descendente y viceversa", "Tocar el sujeto en el modo opuesto", "Tocar el sujeto en otra voz"], a: 1, fb: "La inversión melódica voltea el sujeto: cada intervalo sube donde bajaba y viceversa. Si el sujeto sube una tercera y luego baja una segunda, la inversión baja una tercera y luego sube una segunda. Es una técnica del contrapunto doble." },
  { q: "¿Cuántas voces tiene generalmente una fuga de Bach del Clave Bien Temperado?", opts: ["Siempre 4 voces", "2 a 5 voces según la fuga, más frecuentemente 3 o 4", "Siempre 2 voces", "6 voces como estándar"], a: 1, fb: "Las fugas del Clave Bien Temperado varían entre 2 y 5 voces. La mayoría son a 3 voces (flexibilidad pianística) o 4 voces (riqueza contrapuntística). La fuga a 5 voces es rara y reservada para momentos de grandeza solemne. No hay norma fija — Bach elige según la expresión buscada." },
  { q: "¿Qué es el 'Clave Bien Temperado' de Bach?", opts: ["Un tratado de afinación de pianos", "Una colección de 48 preludios y fugas (dos volúmenes de 24 pares) en las 24 tonalidades mayores y menores — obra maestra del contrapunto tonal", "Una ópera en 48 actos", "Un método de piano para principiantes"], a: 1, fb: "El Clave Bien Temperado (Das Wohltemperierte Klavier) comprende dos colecciones de 24 preludios y fugas cada una, cubriendo todas las tonalidades mayores y menores. Bach lo compuso para demostrar la viabilidad del temperamento igual y para enseñar el contrapunto. Es la 'biblia' del pianista clásico." },
  { q: "¿Qué es 'El Arte de la Fuga' BWV 1080?", opts: ["Una ópera de Bach", "El testamento fugal de Bach — 14 fugas (Contrapuncti) y 4 cánones sobre un único sujeto cromático, inacabado a su muerte", "Una colección de 48 corales", "Un concierto para órgano"], a: 1, fb: "El Arte de la Fuga es la obra testamento de Bach, compuesta en sus últimos años. Todos los Contrapuncti (fugas) están basados en el mismo sujeto: Re–La–Fa–Re en Do menor. La obra se interrumpe en mitad de una fuga cuando se introduce el motivo B-A-C-H (Sib–La–Do–Si) — Bach no pudo terminarla." },
  { q: "¿Cómo identificar el sujeto en la exposición de una fuga al escuchar?", opts: ["Es siempre la voz más grave", "Es la primera melodía presentada sola sin acompañamiento, en cualquier voz", "Es el motivo más repetido", "Es la línea de bajo"], a: 1, fb: "En la exposición, la primera voz que entra (cualquiera que sea su tesitura) presenta el sujeto solo, sin ningún acompañamiento. Es la única melodía que se escucha. Luego la 2ª voz entra con la respuesta (mientras la 1ª continúa con el contrasujeto). Identificar la entrada solitaria inicial = identificar el sujeto." },
  { q: "En una fuga a 4 voces, ¿cuál es el orden típico de las entradas en la exposición?", opts: ["Siempre soprano → alto → tenor → bajo", "Variable — a menudo agudo→grave o grave→agudo, alternando tónica y dominante: S-A-T-B o B-T-A-S", "Siempre las voces por parejas simultáneas", "Siempre el bajo primero"], a: 1, fb: "El orden de las entradas en la exposición varía según la fuga. Bach alterna a menudo entre voces agudas y graves (S-B-A-T o B-S-T-A) para crear variedad. El orden tónica-dominante alterna: voz 1 (sujeto, tónica), voz 2 (respuesta, dominante), voz 3 (sujeto, tónica), voz 4 (respuesta, dominante)." },
  { q: "¿Qué es la 'codeta' en la exposición de una fuga?", opts: ["La conclusión de la fuga", "Un breve pasaje de transición entre las entradas de la exposición, que permite modular brevemente hacia la dominante antes de la entrada de la respuesta", "El contrasujeto final", "La estrecha final"], a: 1, fb: "La codeta es un breve pasaje intersticial en la exposición, entre el final del sujeto y el comienzo de la respuesta. Permite una transición armónica suave (generalmente hacia la dominante) antes de que entre la 2ª voz. No todas las fugas tienen codeta — algunas tienen entradas directas sin transición." },
  { q: "¿Cómo termina generalmente una fuga?", opts: ["Por una cadencia plagal únicamente", "Por una cadencia perfecta (V→I) con a veces un pedal de tónica final, a menudo un acorde con tercera picarda en modo menor", "Por una repetición del sujeto al principio", "Por un silencio"], a: 1, fb: "La fuga termina generalmente con una cadencia perfecta fuerte (V→I). En modo menor, Bach termina a menudo con la 'tercera picarda' (Do# en Do menor → acorde de Do mayor). Un pedal de tónica en el bajo puede sostener los últimos compases, creando estabilidad final tras toda la tensión contrapuntística." },
  { q: "¿Qué es el 'retrógrado' de un sujeto de fuga?", opts: ["El sujeto tocado con el ritmo invertido", "El sujeto tocado hacia atrás — desde la última nota hasta la primera", "El sujeto transportado una quinta abajo", "El sujeto fragmentado en motivos cortos"], a: 1, fb: "El retrógrado (o cancrizans) consiste en tocar el sujeto desde la última nota hasta la primera. Si el sujeto es Do–Re–Mib–Fa, el retrógrado es Fa–Mib–Re–Do. Es una técnica de contrapunto canónico, muy utilizada en El Arte de la Fuga. Combinado con la inversión, se obtiene el retrógrado invertido." },
  { q: "¿Qué se llama 'contrapunto doble' o 'contrapunto invertible'?", opts: ["Un contrapunto con dos sujetos diferentes", "Un contrapunto donde las dos líneas pueden intercambiarse (una pasa a la voz grave, la otra a la aguda) sin crear faltas de contrapunto", "Un contrapunto en modo menor", "Un contrapunto a la octava"], a: 1, fb: "El contrapunto doble (o invertible) permite intercambiar las voces: la voz superior pasa a voz inferior y viceversa. Para que esto funcione, los intervalos entre las voces deben seguir siendo consonantes en ambas disposiciones. Esta es la condición para que un contrasujeto esté 'perfectamente' construido." },
  { q: "En 'El Arte de la Fuga', ¿cuál es el sujeto que recorre todas las fugas?", opts: ["Sol–Sol–Sol–Mib (como Beethoven)", "Re–La–Fa–Re en Do menor (el sujeto unificado de toda la obra)", "Do–Re–Mi–Fa (escala ascendente)", "Mi–Fa–Re–Sol (motivo de 4 notas)"], a: 1, fb: "El sujeto unificado de El Arte de la Fuga es Re–La–Fa–Re en Do menor. Las 14 fugas (Contrapuncti) y los 4 cánones son desarrollos contrapuntísticos de este mismo sujeto. La obra demuestra el agotamiento de las posibilidades fugales de un solo material temático." },
  { q: "¿Qué es un 'canon' en contrapunto, cercano a la fuga?", opts: ["Una pieza para instrumentos de viento metal únicamente", "Una imitación estricta y continua — la voz 2 sigue a la voz 1 con exactamente las mismas notas desfasadas en el tiempo, indefinidamente", "Un acorde repetido", "Una secuencia cromática"], a: 1, fb: "Un canon es una imitación estricta y continua: la voz 2 retoma exactamente lo que acaba de tocar la voz 1 (o a la quinta, o en inversión...). A diferencia de la fuga, la imitación del canon es total y permanente. Ejemplos célebres: Canon de Pachelbel, Row Your Boat, Frère Jacques en canon." },
  { q: "¿Cuándo se dice que una fuga utiliza un 'sujeto tonal' en lugar de un 'sujeto real'?", opts: ["Cuando el sujeto modula hacia otra tonalidad", "Cuando el sujeto comienza en la dominante — la respuesta comenzará entonces en la tónica para preservar la centralidad tonal", "Cuando el sujeto no tiene contrasujeto", "Cuando el sujeto es cromático"], a: 1, fb: "Un sujeto que se abre en la dominante (Sol en Do mayor) recibe una 'respuesta tonal' en lugar de real: la respuesta comienza en la tónica (Do) en vez de en la dominante (Re). Esta modificación mantiene Do como centro y evita que la respuesta parezca modular prematuramente hacia Sol mayor." },
];

const questionsDe: Question[] = [
  { q: "Welche Stimmen bilden einen 4-stimmigen Bach-Choral (SATB)?", opts: ["Sopran, Alt, Tenor, Bass", "Sopran, Akkordeon, Tuba, Bariton", "Sopran, Bratschist, Posaunist, Bassist", "G, D, E, H"], a: 0, fb: "SATB steht für Sopran (hohe Frauenstimme), Alt (tiefe Frauenstimme), Tenor (hohe Männerstimme) und Bass (tiefe Männerstimme). Das ist die Standardbesetzung des klassischen Chorals seit dem Mittelalter." },
  { q: "Was muss der Leitton (7. Stufe) im Bach-Stil tun?", opts: ["Zur Dominante absteigen", "Zur Tonika durch einen aufsteigenden Halbtonschritt aufsteigen", "Liegen bleiben", "Zur Mediante springen"], a: 1, fb: "Der Leitton (7. Stufe, z.B. H in C-Dur) MUSS zur Tonika (C) durch einen aufsteigenden Halbtonschritt auflösen. Das ist die strengste Regel des Barockstils — sie zu verletzen ist ein schwerer Stilfehler." },
  { q: "Wie muss die Dominantseptime in einem Bach-Choral auflösen?", opts: ["Sie steigt zur Grundton der Tonika auf", "Sie steigt stufenweise ab", "Sie kann sich frei bewegen", "Sie springt eine Quinte"], a: 1, fb: "Die Dominantseptime (z.B. F in G7) MUSS stufenweise zur Terz der Tonika (E in C-Dur) absteigen. Das ist die grundlegende Auflösungsgeste des klassischen tonalen Kontrapunkts." },
  { q: "Was ist die 'Grundtonverdoppelung' in einem 4-stimmigen Choral?", opts: ["Den Grundton zweimal hintereinander spielen", "Den Grundton des Akkords zwei verschiedenen Stimmen geben", "Den Bass lauter machen", "Den ersten Akkord wiederholen"], a: 1, fb: "Die Grundtonverdoppelung bedeutet, dass zwei Stimmen dieselbe Note (den Grundton des Akkords) in Oktave oder Unisono singen. Das ist die Standardwahl, um einen 3-stimmigen Akkord (Dreiklang) auf 4 Stimmen zu vervollständigen." },
  { q: "Warum sind parallele Quinten und Oktaven im Bach-Choral verboten?", opts: ["Sie sind zu schwer zu singen", "Sie erzeugen eine Verschmelzung der Stimmen, die deren Unabhängigkeit aufhebt — der Kontrapunkt verlangt eigenständige Stimmen", "Sie sind zu hoch für Chorsänger", "Sie erzeugen eine unerträgliche Dissonanz"], a: 1, fb: "Parallele Quinten und Oktaven verschmelzen zwei Stimmen akustisch zu einer — sie verlieren ihre Unabhängigkeit. Der 4-stimmige Kontrapunkt verlangt aber 4 eigenständige und erkennbare Linien. Bach kann sehr gelegentlich parallele Quinten schreiben, aber das ist die Ausnahme, nie die Regel." },
  { q: "Was ist die 4-stufige Methode zur Harmonisierung eines Chorals?", opts: ["1-Melodie 2-Akkorde 3-Rhythmus 4-Dynamik", "1-Tonart und Kadenzen bestimmen 2-Bass schreiben 3-Alt/Tenor vervollständigen 4-Regeln überprüfen", "1-Bass 2-Sopran 3-Alt 4-Tenor", "1-Modus wählen 2-Melodie schreiben 3-Harmonisieren 4-Überarbeiten"], a: 1, fb: "Die akademische 4-stufige Methode: 1/ Tonart bestimmen und Kadenzpunkte markieren; 2/ Bass schreiben (das harmonische Fundament); 3/ Alt und Tenor vervollständigen und Fehler vermeiden; 4/ ALLE Regeln überprüfen (Parallelen, Verdopplungen, Leitton, Septime)." },
  { q: "In welchem Register liegt die Tenorstimme im SATB-Choral?", opts: ["Violinschlüssel, normale Oktave", "Violinschlüssel, klingt eine Oktave tiefer (Ottava bassa)", "Bassschlüssel 4. Linie", "Altschlüssel 3. Linie"], a: 1, fb: "Der Tenor wird im Violinschlüssel mit einer kleinen '8' darunter notiert (Ottava bassa) — er klingt eine Oktave tiefer als notiert. In der SATB-Chorpartitur teilen Sopran und Alt ein System (Hälse oben/unten), Tenor und Bass ebenso." },
  { q: "Darf der Bass in einem Bach-Choral eine Quinte springen?", opts: ["Nein — der Bass muss immer schrittweise gehen", "Ja — Quint- und Quartsprünge im Bass sind erlaubt und typisch für Bachs Stil", "Nur in einer Kadenz", "Nur beim ersten Akkord"], a: 1, fb: "Quart- und Quintsprünge im Bass sind nicht nur erlaubt, sondern charakteristisch für Bachs Stil — sie markieren starke Harmoniewechsel. Schrittweise Bassbewegungen dienen Durchgangsakkorden; springende Bässe markieren strukturelle Harmonien." },
  { q: "Was ist der 'Leitton' in der C-Dur-Tonleiter?", opts: ["C (Tonika)", "G (Dominante)", "H (natürliche siebte Stufe)", "F (Subdominante)"], a: 2, fb: "Der Leitton ist die 7. Stufe der Tonleiter — H in C-Dur. Er verdankt seinen Namen seiner tonalen 'Empfindlichkeit': er liegt einen Halbton von der Tonika entfernt (H → C) und hat daher eine starke Anziehung zu ihr. Nicht verwechseln mit der Unterseptime (B in C-Dur)." },
  { q: "Wie vermeidet man parallele Oktaven zwischen Sopran und Bass im Choral?", opts: ["Die Stimmen immer in die gleiche Richtung bewegen", "Gegen- oder Seitenbewegung verwenden — wenn der Bass aufsteigt, geht der Sopran runter (oder bleibt)", "Immer springen statt schrittweise gehen", "Systematisch die Terz verdoppeln"], a: 1, fb: "Gegenbewegung (eine Stimme steigt auf, die andere ab) ist der beste Weg, parallele Oktaven und Quinten zu vermeiden. Wenn der Bass eine Quinte aufsteigt, sollte der Sopran absteigen. Seitenbewegung (eine Stimme bleibt) ist ebenfalls sicher." },
  { q: "Was ist ein 'harmonisierter Choral' von Bach?", opts: ["Ein von Bach komponierter Choral", "Eine vorhandene (oft lutherische) Melodie, die Bach 4-stimmig harmonisiert hat", "Ein Choral, der solo auf der Orgel gespielt wird", "Ein Choral ohne Text"], a: 1, fb: "Bach hat die Melodien seiner Choräle nicht selbst komponiert — er hat sie harmonisiert. Diese Melodien sind bereits vorhandene lutherische Kirchenlieder (oft aus dem 16. Jahrhundert). Bach hat ~400 SATB-Harmonisierungen dieser Melodien erstellt, die als Gipfel des Genres gelten." },
  { q: "Wie erkennt man die 'Atempunkte' in einem Choral, um Kadenzen zu platzieren?", opts: ["Nur an den Taktstrichen", "An Punkten, Kommas und Phrasenenden im Text — die Kadenz entspricht der verbalen Interpunktion", "Alle 4 Takte", "Nur am Anfang und am Ende"], a: 1, fb: "In einem Choral folgen die Atempunkte dem gesungenen Text. Ein Komma → Halbschluss oder unvollkommene Kadenz (Suspension). Ein Punkt → vollkommene Kadenz (Schluss). Bach bildet die musikalische Interpunktion rigoros auf die verbale Interpunktion ab — die Musik atmet wie der Satz." },
  { q: "Welche Verdoppelung muss im Dominantakkord (V) unbedingt vermieden werden?", opts: ["Den Grundton verdoppeln", "Die Terz verdoppeln", "Den Leitton verdoppeln", "Die Quinte verdoppeln"], a: 2, fb: "Den Leitton (7. Stufe) im Dominantakkord zu verdoppeln ist ein schwerer Fehler: beide Leittöne müssen zur Tonika aufsteigen, was zwangsläufig parallele Oktaven erzeugt. Daher wird der Leitton nicht verdoppelt — stattdessen Grundton oder Quinte verdoppeln." },
  { q: "In welchem Kontext erlaubt Bach die Quintbewegung zwischen Bass und Tenor?", opts: ["Niemals", "In authentisch-plagalen Kadenzen", "Wenn die Bewegung gegensinnig oder seitwärts ist (direkte Quinten vermieden)", "Nur im Sopran"], a: 2, fb: "Verdeckte Quinten (zwei Stimmen erreichen eine Quinte durch direkte Bewegung) sind zu vermeiden, besonders zwischen Außenstimmen. Eine Quinte in Gegenbewegung (eine steigt auf, die andere ab) ist jedoch nicht parallel. Bach wendet diese Regel streng bei Außenstimmen und flexibler bei Innenstimmen an." },
  { q: "Wie realisiert man einen 4-stimmigen Dominantakkord in C-Dur (G7: G–H–D–F)?", opts: ["G–G–H–D (Grundton verdoppeln, Septime weglassen)", "G–H–D–F (alle Töne, keine Verdoppelung)", "G–H–G–D (Grundton verdoppeln, Septime weglassen)", "G–F–D–H (Umkehrung)"], a: 1, fb: "G7 enthält 4 verschiedene Töne (G–H–D–F), also können in 4 Stimmen alle Töne ohne Verdoppelung geschrieben werden. Das ist sogar vorzuziehen beim Dominantakkord, da die Septime (F) für die Auflösung entscheidend ist — nicht weglassen. Bass: G. Sopran: G, H oder D je nach gegebener Melodie." },
  { q: "Was ist das 'Thema' einer Fuge?", opts: ["Das literarische Argument des Textes", "Das Hauptthema, das zu Beginn allein in der Tonika ohne Begleitung vorgestellt wird", "Die harmonische Antwort", "Das Kontrasubjekt"], a: 1, fb: "Das Thema (Subject) ist das Hauptthema der Fuge — meist 1 bis 4 Takte lang. Es wird zu Beginn von einer einzigen Stimme allein, ohne Begleitung, in der Tonika vorgestellt. Alles andere in der Fuge basiert auf diesem Ausgangsmaterial." },
  { q: "Was ist der Unterschied zwischen 'realer Antwort' und 'tonaler Antwort'?", opts: ["Die reale Antwort liegt in der richtigen Tonhöhe, die tonale ist falsch", "Die reale Antwort ist eine exakte Transposition des Themas zur Dominante; die tonale Antwort verändert bestimmte Intervalle leicht, um eine vorzeitige Modulation zu vermeiden", "Sie sind identisch", "Die tonale Antwort ist länger"], a: 1, fb: "Reale Antwort: exakte Transposition des Themas zur Dominante (Quinte höher). Tonale Antwort: Transposition mit Veränderung eines oder zweier Intervalle — oft wenn das Thema auf der Dominante (Quinte) beginnt, beginnt der Anfang der Antwort auf der Tonika, um die Tonalität zu verankern." },
  { q: "Was ist das 'Kontrasubjekt'?", opts: ["Ein zweites unabhängiges Thema", "Die Melodie, die gleichzeitig die Antwort begleitet — im Kontrapunkt mit Thema oder Antwort erscheint sie bei jeder Themeneintritt wieder", "Das rückwärts gespielte Thema", "Der Bass des Themas"], a: 1, fb: "Das Kontrasubjekt ist der Kontrapunkt, der zur Begleitung der Antwort (und des Themas) geschrieben wurde. Es steht im Doppelkontrapunkt mit dem Thema: sie können vertauscht werden (das Thema geht zur Kontrasubjektstimme und umgekehrt), ohne Fehler zu erzeugen. Seine Beständigkeit ist das Merkmal einer gut konstruierten Fuge." },
  { q: "Was nennt man die 'Exposition' in einer Fuge?", opts: ["Der Eröffnungsabschnitt, in dem alle Stimmen sukzessive mit dem Thema eintreten", "Die zentrale Durchführung", "Der Schluss der Fuge", "Das erste Zwischenspiel"], a: 0, fb: "Die Exposition ist der Eröffnungsabschnitt der Fuge, in dem alle Stimmen nacheinander mit dem Thema (in der Tonika) oder der Antwort (in der Dominante) eintreten. In einer 4-stimmigen Fuge umfasst die Exposition 4 Eintritte, die Thema (I) und Antwort (V) abwechseln." },
  { q: "Was ist ein 'Zwischenspiel' in einer Fuge?", opts: ["Ein Abschnitt, in dem das Thema fehlt — Verbindungsmusik zwischen zwei Themeneintritten, oft sequenziell und modulierend", "Eine weitere Exposition", "Die Wiederkehr des Themas in Augmentation", "Das Kontrasubjekt allein"], a: 0, fb: "Ein Zwischenspiel (Divertimento) ist ein Abschnitt der Fuge, in dem das vollständige Thema nicht erscheint. Oft hört man Fragmente des Themas oder Kontrasubjekts in modulierenden Sequenzen. Zwischenspiele verbinden die Themeneintritt und modulieren zu anderen Tonarten." },
  { q: "Was ist eine 'Engführung' (Stretto)?", opts: ["Das zweimal hintereinander gespielte Thema", "Das Überlappen von Themeneintritten — die 2. Stimme tritt mit dem Thema ein, bevor die 1. Stimme ihres beendet hat", "Das Thema in Augmentation", "Der Schluss der Fuge"], a: 1, fb: "Die Engführung (Stretto) ist eine Intensivierungstechnik: Themeneintritt überlappen sich und erzeugen eine zeitliche Verdichtung. Die 2. Stimme beginnt das Thema, bevor die 1. es beendet hat. Die Engführung wird oft für den Höhepunkt der Fuge reserviert, um maximale Spannung zu erzeugen." },
  { q: "Was ist die 'Augmentation' eines Fugenthemas?", opts: ["Das Thema lauter spielen", "Das Thema in doppelten Notenwerten spielen — jede Viertel wird zur Halben, jede Achtel zur Viertel", "Das Thema höher transponieren", "Das Thema in einem anderen Modus spielen"], a: 1, fb: "Augmentation bedeutet, das Thema in verdoppelten rhythmischen Werten zu spielen. Wenn das Originalthema lautet: Viertel–Achtel–Achtel–Viertel, ergibt die Augmentation: Halbe–Viertel–Viertel–Halbe. Die Wirkung ist, das Thema zu vergrößern und zu feierlichen, wird oft im Schlussklimaks verwendet." },
  { q: "Was ist die 'Umkehrung' eines Fugenthemas?", opts: ["Das Thema rückwärts in der Zeit spielen", "Das Thema melodisch umkehren — jedes aufsteigende Intervall wird absteigend und umgekehrt", "Das Thema im entgegengesetzten Modus spielen", "Das Thema in einer anderen Stimme spielen"], a: 1, fb: "Die melodische Umkehrung kehrt das Thema um: jedes Intervall steigt auf, wo es abstieg und umgekehrt. Wenn das Thema eine Terz aufsteigt und dann eine Sekunde absteigt, steigt die Umkehrung eine Terz ab und dann eine Sekunde auf. Es ist eine Technik des Doppelkontrapunkts." },
  { q: "Wie viele Stimmen hat eine Bach-Fuge aus dem Wohltemperierten Klavier generell?", opts: ["Immer 4 Stimmen", "2 bis 5 Stimmen je nach Fuge, am häufigsten 3 oder 4", "Immer 2 Stimmen", "Standardmäßig 6 Stimmen"], a: 1, fb: "Die Fugen des Wohltemperierten Klaviers variieren zwischen 2 und 5 Stimmen. Die meisten sind 3-stimmig (pianistische Flexibilität) oder 4-stimmig (kontrapunktischer Reichtum). Die 5-stimmige Fuge ist selten und feierlichen Momenten vorbehalten. Es gibt keine feste Norm — Bach wählt je nach angestrebtem Ausdruck." },
  { q: "Was ist Bachs 'Wohltemperiertes Klavier'?", opts: ["Eine Abhandlung über Klavierstimmung", "Eine Sammlung von 48 Präludien und Fugen (zwei Bände à 24 Paare) in allen 24 Dur- und Molltonarten — Meisterwerk des tonalen Kontrapunkts", "Eine Oper in 48 Akten", "Eine Klavierschule für Anfänger"], a: 1, fb: "Das Wohltemperierte Klavier umfasst zwei Sammlungen à 24 Präludien und Fugen, die alle Dur- und Molltonarten abdecken. Bach komponierte es, um die Praktikabilität der gleichschwebenden Temperatur zu demonstrieren und Kontrapunkt zu lehren. Es ist die 'Bibel' des klassischen Pianisten." },
  { q: "Was ist 'Die Kunst der Fuge' BWV 1080?", opts: ["Eine Oper von Bach", "Bachs kontrapunktisches Testament — 14 Fugen (Contrapuncti) und 4 Kanons über ein einziges chromatisches Thema, unvollendet bei seinem Tod", "Eine Sammlung von 48 Chorälen", "Ein Orgelkonzert"], a: 1, fb: "Die Kunst der Fuge ist Bachs Testamentswerk, in seinen letzten Jahren komponiert. Alle Contrapuncti (Fugen) basieren auf demselben Thema: D–A–F–D in c-Moll. Das Werk bricht mitten in einer Fuge ab, die das Motiv B–A–C–H (B–A–C–H) einführt — Bach konnte es nicht mehr vollenden." },
  { q: "Wie erkennt man das Thema in der Exposition einer Fuge beim Hören?", opts: ["Es ist immer die tiefste Stimme", "Es ist die erste Melodie, die allein ohne Begleitung in einer beliebigen Stimme präsentiert wird", "Es ist das am häufigsten wiederholte Motiv", "Es ist die Basslinie"], a: 1, fb: "In der Exposition präsentiert die erste eintretende Stimme (egal welche Lage) das Thema allein, ohne jede Begleitung. Es ist die einzige hörbare Melodie. Dann tritt die 2. Stimme mit der Antwort ein (während die 1. mit dem Kontrasubjekt fortfährt). Den anfänglichen Soloauftritt zu identifizieren = das Thema zu identifizieren." },
  { q: "In einer 4-stimmigen Fuge, was ist die typische Reihenfolge der Eintritte in der Exposition?", opts: ["Immer Sopran → Alt → Tenor → Bass", "Variabel — oft hoch→tief oder tief→hoch, abwechselnd Tonika und Dominante: S-A-T-B oder B-T-A-S", "Immer paarweise gleichzeitig", "Immer Bass zuerst"], a: 1, fb: "Die Reihenfolge der Eintritte in der Exposition variiert je nach Fuge. Bach wechselt oft zwischen hohen und tiefen Stimmen (S-B-A-T oder B-S-T-A), um Abwechslung zu schaffen. Die Tonika-Dominante-Reihenfolge alterniert: Stimme 1 (Thema, Tonika), Stimme 2 (Antwort, Dominante), Stimme 3 (Thema, Tonika), Stimme 4 (Antwort, Dominante)." },
  { q: "Was ist die 'Codetta' in der Exposition einer Fuge?", opts: ["Der Schluss der Fuge", "Eine kurze Übergangspassage zwischen den Eintritten der Exposition, die eine kurze Modulation zur Dominante ermöglicht, bevor die Antwort eintritt", "Das abschließende Kontrasubjekt", "Die abschließende Engführung"], a: 1, fb: "Die Codetta ist eine kurze Zwischenpassage in der Exposition, zwischen dem Ende des Themas und dem Beginn der Antwort. Sie ermöglicht einen sanften harmonischen Übergang (meist zur Dominante), bevor die 2. Stimme eintritt. Nicht alle Fugen haben eine Codetta — manche haben direkte Eintritte ohne Übergang." },
  { q: "Wie endet eine Fuge in der Regel?", opts: ["Mit einer plagalen Kadenz ausschließlich", "Mit einer vollkommenen Kadenz (V→I), manchmal mit einem abschließenden Tonika-Orgelpunkt, oft mit Durterz im Mollmodus (picardische Terz)", "Mit einer Wiederholung des Themas am Anfang", "Mit einer Pause"], a: 1, fb: "Die Fuge endet in der Regel mit einer starken vollkommenen Kadenz (V→I). Im Mollmodus schließt Bach oft mit der 'picardischen Terz' (Cis in c-Moll → C-Dur-Akkord). Ein Tonika-Orgelpunkt im Bass kann die letzten Takte stützen und nach all der kontrapunktischen Spannung abschließende Stabilität schaffen." },
  { q: "Was ist der 'Krebs' (Rückwärtsbewegung) eines Fugenthemas?", opts: ["Das Thema mit umgekehrtem Rhythmus gespielt", "Das Thema rückwärts gespielt — von der letzten Note zur ersten", "Das Thema eine Quinte tiefer transponiert", "Das Thema in kurze Motive fragmentiert"], a: 1, fb: "Der Krebs (Cancrizans) besteht darin, das Thema von der letzten Note zur ersten zu spielen. Wenn das Thema C–D–Es–F lautet, ist der Krebs F–Es–D–C. Es ist eine kanonische Kontrapunkttechnik, die in der Kunst der Fuge weit verbreitet ist. In Kombination mit der Umkehrung erhält man den Krebsumkehrung." },
  { q: "Was nennt man 'doppelter Kontrapunkt' oder 'umkehrbarer Kontrapunkt'?", opts: ["Ein Kontrapunkt mit zwei verschiedenen Themen", "Ein Kontrapunkt, bei dem die zwei Linien vertauscht werden können (eine geht in die Tiefstimme, die andere in die Hohotstimme), ohne Kontrapunktfehler zu erzeugen", "Ein Kontrapunkt in Mollmodus", "Ein Kontrapunkt in der Oktave"], a: 1, fb: "Doppelter (umkehrbarer) Kontrapunkt erlaubt das Vertauschen der Stimmen: die Oberstimme geht in die Unterstimme und umgekehrt. Damit das funktioniert, müssen die Intervalle zwischen den Stimmen in beiden Anordnungen konsonant bleiben. Das ist die Bedingung dafür, dass ein Kontrasubjekt 'perfekt' konstruiert ist." },
  { q: "Welches Thema durchzieht in 'Die Kunst der Fuge' alle Fugen?", opts: ["G–G–G–Es (wie Beethoven)", "D–A–F–D in c-Moll (das einheitliche Thema des gesamten Werkes)", "C–D–E–F (aufsteigende Tonleiter)", "E–F–D–G (4-Noten-Motiv)"], a: 1, fb: "Das einheitliche Thema der Kunst der Fuge ist D–A–F–D in c-Moll. Alle 14 Fugen (Contrapuncti) und 4 Kanons sind kontrapunktische Entwicklungen dieses selben Themas. Das Werk demonstriert die Erschöpflichkeit der Fugenmöglichkeiten aus einem einzigen thematischen Material." },
  { q: "Was ist ein 'Kanon' im Kontrapunkt, nahe der Fuge?", opts: ["Ein Stück nur für Blechblasinstrumente", "Strenge und kontinuierliche Imitation — Stimme 2 folgt Stimme 1 mit exakt denselben Noten zeitversetzt, unbegrenzt", "Ein wiederholter Akkord", "Eine chromatische Sequenz"], a: 1, fb: "Ein Kanon ist strenge und kontinuierliche Imitation: Stimme 2 nimmt genau das auf, was Stimme 1 gerade gespielt hat (oder in der Quinte, oder umgekehrt...). Anders als bei der Fuge ist die kanonische Imitation total und dauerhaft. Berühmte Beispiele: Pachelbels Kanon, Row Your Boat, Bruder Jakob als Kanon." },
  { q: "Wann verwendet eine Fuge ein 'tonales Thema' statt eines 'realen Themas'?", opts: ["Wenn das Thema in eine andere Tonart moduliert", "Wenn das Thema auf der Dominante beginnt — die Antwort beginnt dann auf der Tonika, um die tonale Zentralität zu erhalten", "Wenn das Thema kein Kontrasubjekt hat", "Wenn das Thema chromatisch ist"], a: 1, fb: "Ein Thema, das sich auf der Dominante (G in C-Dur) öffnet, erhält eine 'tonale Antwort' statt einer realen: die Antwort beginnt auf der Tonika (C) statt auf der Dominante (D). Diese Modifikation hält C als Zentrum bei und verhindert, dass die Antwort prematurly nach G-Dur zu modulieren scheint." },
];

const questionsIt: Question[] = [
  { q: "In un corale Bach a 4 voci, quali voci compongono il corale SATB?", opts: ["Soprano, Contralto, Tenore, Basso", "Soprano, Fisarmonica, Tuba, Baritono", "Soprano, Violista, Trombonista, Contrabbassista", "Sol, Re, Mi, Si"], a: 0, fb: "SATB sta per Soprano (voce femminile acuta), Contralto (voce femminile grave), Tenore (voce maschile acuta) e Basso (voce maschile grave). È la formazione standard del corale classico dal Medioevo." },
  { q: "Nello stile Bach, cosa deve fare la sensibile (7° grado)?", opts: ["Scendere verso la dominante", "Salire verso la tonica per semitono ascendente", "Restare ferma", "Saltare verso la mediante"], a: 1, fb: "La sensibile (7° grado, es. Si in Do maggiore) DEVE risolvere verso la tonica (Do) per semitono ascendente. È la regola più severa dello stile barocco — violarla è una grave mancanza stilistica." },
  { q: "Come deve risolvere la settima di dominante in un corale Bach?", opts: ["Sale verso la fondamentale della tonica", "Scende per moto congiunto", "Può andare ovunque", "Salta una quinta"], a: 1, fb: "La 7ª di dominante (es. Fa in G7) DEVE scendere per grado congiunto verso la terza della tonica (Mi in Do Magg). Questo è il gesto risolutivo fondamentale del contrappunto tonale classico." },
  { q: "Cos'è il 'raddoppio della fondamentale' in un corale a 4 voci?", opts: ["Suonare la fondamentale due volte di seguito", "Dare la fondamentale dell'accordo a due voci diverse", "Raddoppiare il volume del basso", "Ripetere il primo accordo"], a: 1, fb: "Raddoppiare la fondamentale significa che due voci cantano la stessa nota (la fondamentale dell'accordo) all'ottava o all'unisono. È la scelta predefinita per completare un accordo di 3 suoni (triade) su 4 voci." },
  { q: "Perché le quinte e le ottave parallele sono vietate nel corale Bach?", opts: ["Sono troppo difficili da cantare", "Creano una fusione delle voci che sopprime l'indipendenza delle linee — il contrappunto esige voci distinte", "Sono troppo acute per i coristi", "Creano una dissonanza insopportabile"], a: 1, fb: "Le quinte e le ottave parallele fondono acusticamente due voci in una sola — perdono la loro indipendenza. Tuttavia il contrappunto a 4 voci richiede 4 linee distinte e riconoscibili. Bach può scrivere quinte parallele molto occasionalmente, ma è l'eccezione, mai la regola." },
  { q: "Qual è il metodo di armonizzazione di un corale in 4 fasi?", opts: ["1-Melodia 2-Accordi 3-Ritmo 4-Dinamica", "1-Identificare tonalità e cadenze 2-Collocare il basso 3-Completare contralto/tenore 4-Verificare le regole", "1-Basso 2-Soprano 3-Contralto 4-Tenore", "1-Scegliere il modo 2-Scrivere la melodia 3-Armonizzare 4-Revisionare"], a: 1, fb: "Il metodo accademico in 4 fasi: 1/ Identificare la tonalità e segnare i punti cadenziali; 2/ Scrivere il basso (la fondazione armonica); 3/ Completare contralto e tenore evitando errori; 4/ Verificare TUTTE le regole (parallele, raddoppi, sensibile, 7ª)." },
  { q: "In quale registro si colloca la voce di tenore in un corale SATB?", opts: ["Chiave di violino, ottava normale", "Chiave di violino, suonando un'ottava più in basso (ottava bassa)", "Chiave di basso 4ª riga", "Chiave di contralto 3ª riga"], a: 1, fb: "Il tenore è scritto in chiave di violino con un piccolo '8' sotto (ottava bassa) — suona un'ottava più in basso di quanto scritto. Nella partitura SATB corale, soprano e contralto condividono un pentagramma (gambi in su/giù) e tenore+basso allo stesso modo." },
  { q: "Il basso può saltare una quinta in un corale Bach?", opts: ["No — il basso deve sempre procedere per gradi congiunti", "Sì — i salti di quinta e quarta al basso sono permessi e frequenti nello stile Bach", "Solo in cadenza", "Solo se è il primo accordo"], a: 1, fb: "I salti di quarta e quinta al basso non solo sono permessi, ma sono caratteristici dello stile Bach — segnano i forti cambi armonici. Il moto per gradi del basso serve per gli accordi di passaggio; il basso saltato per le armonie strutturali." },
  { q: "Cos'è la 'sensibile' nella scala di Do maggiore?", opts: ["Il Do (tonica)", "Il Sol (dominante)", "Il Si (settimo grado naturale)", "Il Fa (sottodominante)"], a: 2, fb: "La sensibile è il 7° grado della scala — Si in Do maggiore. Deve il suo nome alla sua 'sensibilità' tonale: si trova a un semitono dalla tonica (Si → Do) e ha quindi una forte attrazione verso di essa. Non confondere con la sottosensibile (Sib in Do maggiore)." },
  { q: "Come evitare le ottave parallele tra soprano e basso in un corale?", opts: ["Muovere sempre le voci nella stessa direzione", "Usare moti contrari od obliqui — se il basso sale, il soprano scende (o rimane)", "Saltare sempre piuttosto che procedere per gradi", "Raddoppiare sistematicamente la terza"], a: 1, fb: "Il moto contrario (una voce sale, l'altra scende) è il modo migliore per evitare ottave e quinte parallele. Se il basso sale di una quinta, il soprano dovrebbe scendere. Il moto obliquo (una voce ferma) è anch'esso sicuro." },
  { q: "Cos'è un 'corale armonizzato' di Bach?", opts: ["Un corale composto da Bach", "Una melodia preesistente (spesso luterana) armonizzata a 4 voci da Bach", "Un corale suonato all'organo solo", "Un corale senza parole"], a: 1, fb: "Bach non ha composto le melodie dei suoi corali — le ha armonizzate. Queste melodie sono inni luterani preesistenti (spesso del XVI secolo). Bach ha prodotto ~400 armonizzazioni SATB di queste melodie, considerate il vertice del genere." },
  { q: "Come identificare i 'punti di respiro' in un corale per collocare le cadenze?", opts: ["Solo alle stanghette di battuta", "Ai punti, virgole e fine di frase nel testo — la cadenza corrisponde alla punteggiatura verbale", "Ogni 4 battute", "Solo all'inizio e alla fine"], a: 1, fb: "In un corale, i punti di respiro seguono il testo cantato. Una virgola → cadenza a metà o imperfetta (sospensione). Un punto → cadenza perfetta (finale). Bach mappa rigorosamente la punteggiatura musicale su quella verbale — la musica respira come la frase." },
  { q: "Quale raddoppio va assolutamente evitato in un accordo di dominante (V)?", opts: ["Raddoppiare la fondamentale", "Raddoppiare la terza", "Raddoppiare la sensibile", "Raddoppiare la quinta"], a: 2, fb: "Raddoppiare la sensibile (7° grado) nell'accordo di dominante è un grave errore: entrambe le sensibili dovranno salire verso la tonica, creando ottave parallele obbligate. Si evita quindi di raddoppiare la sensibile — si raddoppia invece la fondamentale o la quinta." },
  { q: "In quale contesto Bach permette il moto di quinta tra basso e tenore?", opts: ["Mai", "Nelle cadenze autentiche plagali", "Quando il moto è contrario od obliquo (quinte dirette evitate)", "Solo nel soprano"], a: 2, fb: "Le quinte nascoste (due voci raggiungono una quinta per moto diretto) vanno evitate, specialmente tra le voci esterne. Tuttavia una quinta in moto contrario (una sale, l'altra scende) non è parallela. Bach applica questa regola strettamente alle voci esterne e con flessibilità a quelle interne." },
  { q: "Come realizzare un accordo di dominante a 4 voci in Do maggiore (G7: Sol–Si–Re–Fa)?", opts: ["Sol–Sol–Si–Re (raddoppiare fondamentale, omettere 7ª)", "Sol–Si–Re–Fa (tutte le note, nessun raddoppio)", "Sol–Si–Sol–Re (raddoppiare fondamentale, omettere 7ª)", "Sol–Fa–Re–Si (rivolto)"], a: 1, fb: "G7 contiene 4 note distinte (Sol–Si–Re–Fa), quindi a 4 voci si possono scrivere tutte le note senza raddoppio. Ciò è persino preferibile in un accordo di dominante poiché la settima (Fa) è cruciale per la risoluzione — non ometterla. Basso: Sol. Soprano: Sol, Si o Re a seconda della melodia data." },
  { q: "Cos'è il 'soggetto' di una fuga?", opts: ["L'argomento letterario del testo", "Il tema principale, enunciato da solo all'inizio sulla tonica, senza accompagnamento", "La risposta armonica", "Il controsoggetto"], a: 1, fb: "Il soggetto è il tema principale della fuga — generalmente 1-4 battute. È enunciato da solo all'inizio da un'unica voce, senza accompagnamento, sulla tonica. Tutto il resto della fuga è costruito su questo materiale iniziale." },
  { q: "Qual è la differenza tra 'risposta reale' e 'risposta tonale'?", opts: ["La risposta reale è all'altezza giusta, quella tonale è sbagliata", "La risposta reale è una trasposizione esatta del soggetto alla dominante; la risposta tonale modifica leggermente certi intervalli per evitare una modulazione prematura", "Sono identiche", "La risposta tonale è più lunga"], a: 1, fb: "Risposta reale: trasposizione esatta del soggetto alla dominante (quinta sopra). Risposta tonale: trasposizione con modifica di uno o due intervalli — spesso quando il soggetto inizia sulla dominante (quinta), l'inizio della risposta inizia sulla tonica per ancorare la tonalità." },
  { q: "Cos'è il 'controsoggetto'?", opts: ["Un secondo soggetto indipendente", "La melodia che accompagna la risposta simultaneamente — in contrappunto con il soggetto o la risposta, riappare a ogni entrata del soggetto", "Il soggetto suonato al contrario", "Il basso del soggetto"], a: 1, fb: "Il controsoggetto è il contrappunto scritto per accompagnare la risposta (e il soggetto). È in contrappunto doppio con il soggetto: possono essere invertiti (il soggetto passa alla voce del controsoggetto e viceversa) senza creare errori. La sua coerenza è il segno di una fuga ben costruita." },
  { q: "Come si chiama l''esposizione' in una fuga?", opts: ["La sezione di apertura dove tutte le voci entrano successivamente con il soggetto", "Lo sviluppo centrale", "La conclusione della fuga", "Il primo episodio"], a: 0, fb: "L'esposizione è la sezione di apertura della fuga in cui tutte le voci entrano una per una con il soggetto (sulla tonica) o la risposta (sulla dominante). In una fuga a 4 voci, l'esposizione comprende 4 entrate che alternano soggetto (I) e risposta (V)." },
  { q: "Cos'è un 'episodio' in una fuga?", opts: ["Una sezione in cui il soggetto è assente — musica di collegamento tra due entrate del soggetto, spesso sequenziale e modulante", "Un'altra esposizione", "Il ritorno del soggetto in aumentazione", "Il controsoggetto da solo"], a: 0, fb: "Un episodio (o divertimento) è una sezione della fuga in cui il soggetto completo non appare. Si odono spesso frammenti del soggetto o del controsoggetto in sequenze modulanti. Gli episodi servono a collegare le entrate del soggetto e a modulare verso altre tonalità." },
  { q: "Cos'è lo 'stretto'?", opts: ["Il soggetto suonato due volte di seguito", "La sovrapposizione delle entrate del soggetto — la 2ª voce entra con il soggetto prima che la 1ª voce abbia finito il proprio", "Il soggetto in aumentazione", "La conclusione della fuga"], a: 1, fb: "Lo stretto è una tecnica di intensificazione: le entrate del soggetto si sovrappongono, creando una compressione temporale. La 2ª voce inizia il soggetto prima che la 1ª lo abbia terminato. Lo stretto è spesso riservato al climax della fuga per creare la massima tensione." },
  { q: "Cos'è l''aumentazione' di un soggetto di fuga?", opts: ["Suonare il soggetto più forte", "Suonare il soggetto in valori doppi — ogni quarto diventa una metà, ogni ottavo diventa un quarto", "Trasportare il soggetto più in alto", "Suonare il soggetto in un altro modo"], a: 1, fb: "L'aumentazione consiste nel suonare il soggetto in valori ritmici raddoppiati. Se il soggetto originale è: quarto–ottavo–ottavo–quarto, l'aumentazione dà: metà–quarto–quarto–metà. L'effetto è ingrandire e solennizzare il soggetto, spesso utilizzato nel climax finale." },
  { q: "Cos'è l''inversione' di un soggetto di fuga?", opts: ["Suonare il soggetto al contrario nel tempo", "Rovesciare il soggetto melodicamente — ogni intervallo ascendente diventa discendente e viceversa", "Suonare il soggetto nel modo opposto", "Suonare il soggetto in un'altra voce"], a: 1, fb: "L'inversione melodica rovescia il soggetto: ogni intervallo sale dove scendeva e viceversa. Se il soggetto sale di una terza e poi scende di una seconda, l'inversione scende di una terza e poi sale di una seconda. È una tecnica del contrappunto doppio." },
  { q: "Quante voci ha generalmente una fuga di Bach del Clavicembalo Ben Temperato?", opts: ["Sempre 4 voci", "Da 2 a 5 voci a seconda della fuga, più spesso 3 o 4", "Sempre 2 voci", "6 voci come standard"], a: 1, fb: "Le fughe del Clavicembalo Ben Temperato variano tra 2 e 5 voci. La maggior parte sono a 3 voci (flessibilità pianistica) o 4 voci (ricchezza contrappuntistica). La fuga a 5 voci è rara e riservata a momenti di solenne grandiosità. Non c'è norma fissa — Bach sceglie in base all'espressione ricercata." },
  { q: "Cos'è il 'Clavicembalo Ben Temperato' di Bach?", opts: ["Un trattato di accordatura del pianoforte", "Una raccolta di 48 preludi e fughe (due volumi di 24 coppie) in tutte le 24 tonalità maggiori e minori — capolavoro del contrappunto tonale", "Un'opera in 48 atti", "Un metodo di pianoforte per principianti"], a: 1, fb: "Il Clavicembalo Ben Temperato (Das Wohltemperierte Klavier) comprende due raccolte di 24 preludi e fughe ciascuna, coprendo tutte le tonalità maggiori e minori. Bach lo compose per dimostrare la praticabilità del temperamento equabile e per insegnare il contrappunto. È la 'bibbia' del pianista classico." },
  { q: "Cos'è 'L'Arte della Fuga' BWV 1080?", opts: ["Un'opera di Bach", "Il testamento fugale di Bach — 14 fughe (Contrapuncti) e 4 canoni su un unico soggetto cromatico, incompiuto alla sua morte", "Una raccolta di 48 corali", "Un concerto per organo"], a: 1, fb: "L'Arte della Fuga è l'opera testamento di Bach, composta negli ultimi anni. Tutti i Contrapuncti (fughe) si basano sullo stesso soggetto: Re–La–Fa–Re in Do minore. L'opera si interrompe a metà di una fuga che introduce il motivo B-A-C-H (Sib–La–Do–Si) — Bach non riuscì mai a terminarla." },
  { q: "Come identificare il soggetto nell'esposizione di una fuga all'ascolto?", opts: ["È sempre la voce più grave", "È la prima melodia presentata da sola senza accompagnamento, in qualsiasi voce", "È il motivo più ripetuto", "È la linea del basso"], a: 1, fb: "Nell'esposizione, la prima voce che entra (qualunque sia la sua tessitura) presenta il soggetto da solo, senza alcun accompagnamento. È l'unica melodia che si sente. Poi la 2ª voce entra con la risposta (mentre la 1ª continua con il controsoggetto). Identificare l'entrata solitaria iniziale = identificare il soggetto." },
  { q: "In una fuga a 4 voci, qual è l'ordine tipico delle entrate nell'esposizione?", opts: ["Sempre soprano → contralto → tenore → basso", "Variabile — spesso acuto→grave o grave→acuto, alternando tonica e dominante: S-A-T-B o B-T-A-S", "Sempre le voci a coppie simultanee", "Sempre il basso per primo"], a: 1, fb: "L'ordine delle entrate nell'esposizione varia secondo la fuga. Bach alterna spesso tra voci acute e gravi (S-B-A-T o B-S-T-A) per creare varietà. L'ordine tonica-dominante alterna: voce 1 (soggetto, tonica), voce 2 (risposta, dominante), voce 3 (soggetto, tonica), voce 4 (risposta, dominante)." },
  { q: "Cos'è la 'codetta' nell'esposizione di una fuga?", opts: ["La conclusione della fuga", "Un breve passaggio di transizione tra le entrate dell'esposizione, che permette di modulare brevemente verso la dominante prima dell'entrata della risposta", "Il controsoggetto finale", "Lo stretto finale"], a: 1, fb: "La codetta è un breve passaggio interstiziale nell'esposizione, tra la fine del soggetto e l'inizio della risposta. Permette una transizione armonica dolce (generalmente verso la dominante) prima che entri la 2ª voce. Non tutte le fughe hanno una codetta — alcune hanno entrate dirette senza transizione." },
  { q: "Come termina generalmente una fuga?", opts: ["Con una cadenza plagale unicamente", "Con una cadenza perfetta (V→I) con a volte un pedale finale di tonica, spesso un accordo con terza picarda nel modo minore", "Con una ripetizione del soggetto all'inizio", "Con un silenzio"], a: 1, fb: "La fuga termina generalmente con una forte cadenza perfetta (V→I). Nel modo minore, Bach finisce spesso con la 'terza picarda' (Do# in Do minore → accordo di Do maggiore). Un pedale di tonica al basso può sostenere le ultime battute, creando stabilità finale dopo tutta la tensione contrappuntistica." },
  { q: "Cos'è il 'retrogrado' di un soggetto di fuga?", opts: ["Il soggetto suonato con il ritmo invertito", "Il soggetto suonato al contrario — dall'ultima nota alla prima", "Il soggetto trasportato una quinta più in basso", "Il soggetto frammentato in brevi motivi"], a: 1, fb: "Il retrogrado (o cancrizans) consiste nel suonare il soggetto dall'ultima nota alla prima. Se il soggetto è Do–Re–Mib–Fa, il retrogrado è Fa–Mib–Re–Do. È una tecnica di contrappunto canonico, ampiamente usata nell'Arte della Fuga. Combinato con l'inversione, si ottiene il retrogrado invertito." },
  { q: "Cosa si chiama 'contrappunto doppio' o 'contrappunto invertibile'?", opts: ["Un contrappunto con due soggetti diversi", "Un contrappunto in cui le due linee possono essere scambiate (una passa alla voce grave, l'altra all'acuta) senza creare errori contrappuntistici", "Un contrappunto in modo minore", "Un contrappunto all'ottava"], a: 1, fb: "Il contrappunto doppio (o invertibile) permette di scambiare le voci: la voce superiore passa in posizione inferiore e viceversa. Perché ciò funzioni, gli intervalli tra le voci devono restare consonanti in entrambe le disposizioni. È la condizione perché un controsoggetto sia 'perfettamente' costruito." },
  { q: "Ne 'L'Arte della Fuga', qual è il soggetto che percorre tutte le fughe?", opts: ["Sol–Sol–Sol–Mib (come Beethoven)", "Re–La–Fa–Re in Do minore (il soggetto unificato dell'intera opera)", "Do–Re–Mi–Fa (scala ascendente)", "Mi–Fa–Re–Sol (motivo di 4 note)"], a: 1, fb: "Il soggetto unificato dell'Arte della Fuga è Re–La–Fa–Re in Do minore. Tutte le 14 fughe (Contrapuncti) e i 4 canoni sono sviluppi contrappuntistici di questo stesso soggetto. L'opera dimostra l'esaustività delle possibilità fugali di un unico materiale tematico." },
  { q: "Cos'è un 'canone' in contrappunto, affine alla fuga?", opts: ["Un pezzo solo per strumenti a fiato in ottone", "Un'imitazione rigorosa e continua — la voce 2 segue la voce 1 con esattamente le stesse note scaglionate nel tempo, indefinitamente", "Un accordo ripetuto", "Una sequenza cromatica"], a: 1, fb: "Un canone è un'imitazione rigorosa e continua: la voce 2 riprende esattamente ciò che la voce 1 ha appena suonato (o alla quinta, o in inversione...). A differenza della fuga, l'imitazione del canone è totale e permanente. Esempi famosi: Canone di Pachelbel, Row Your Boat, Fra Martino in canone." },
  { q: "Quando si dice che una fuga usa un 'soggetto tonale' piuttosto che un 'soggetto reale'?", opts: ["Quando il soggetto modula verso un'altra tonalità", "Quando il soggetto inizia sulla dominante — la risposta inizierà allora sulla tonica per preservare la centralità tonale", "Quando il soggetto non ha controsoggetto", "Quando il soggetto è cromatico"], a: 1, fb: "Un soggetto che si apre sulla dominante (Sol in Do maggiore) riceve una 'risposta tonale' invece che reale: la risposta inizia sulla tonica (Do) invece che sulla dominante (Re). Questa modifica mantiene Do come centro e impedisce che la risposta sembri modulare prematuramente verso Sol maggiore." },
];

const questionsPt: Question[] = [
  { q: "Num coral Bach a 4 vozes, quais vozes formam o coral SATB?", opts: ["Soprano, Contralto, Tenor, Baixo", "Soprano, Acordeão, Tuba, Barítono", "Soprano, Violetista, Trombonista, Contrabaixista", "Sol, Ré, Mi, Si"], a: 0, fb: "SATB significa Soprano (voz feminina aguda), Contralto (voz feminina grave), Tenor (voz masculina aguda) e Baixo (voz masculina grave). É a formação padrão do coral clássico desde a Idade Média." },
  { q: "No estilo Bach, o que deve fazer a sensível (7.° grau)?", opts: ["Descer para a dominante", "Subir para a tónica por semitom ascendente", "Ficar no lugar", "Saltar para a mediante"], a: 1, fb: "A sensível (7.° grau, ex.: Si em Dó maior) DEVE resolver para a tónica (Dó) por semitom ascendente. É a regra mais rígida do estilo barroco — violá-la é uma falta grave de estilo." },
  { q: "Como deve resolver a sétima de dominante num coral Bach?", opts: ["Sobe para a fundamental da tónica", "Desce por movimento conjunto", "Pode ir para qualquer lado", "Salta uma quinta"], a: 1, fb: "A 7ª de dominante (ex.: Fá em G7) DEVE descer por grau conjunto para a terça da tónica (Mi em Dó Maior). É o gesto resolutivo fundamental do contraponto tonal clássico." },
  { q: "O que é o 'dobramento da fundamental' num coral a 4 vozes?", opts: ["Tocar a fundamental duas vezes seguidas", "Dar a fundamental do acorde a duas vozes diferentes", "Dobrar o volume do baixo", "Repetir o primeiro acorde"], a: 1, fb: "Dobrar a fundamental significa que duas vozes cantam a mesma nota (a fundamental do acorde) à oitava ou em uníssono. É a escolha padrão para completar um acorde de 3 sons (tríade) em 4 vozes." },
  { q: "Por que as quintas e oitavas paralelas são proibidas no coral Bach?", opts: ["São difíceis de cantar", "Criam uma fusão de vozes que suprime a independência das linhas — o contraponto exige vozes distintas", "São demasiado agudas para os coristas", "Criam uma dissonância insuportável"], a: 1, fb: "As quintas e oitavas paralelas fundem acusticamente duas vozes numa só — perdem a sua independência. O contraponto a 4 vozes exige porém 4 linhas distintas e identificáveis. Bach pode escrever quintas paralelas muito ocasionalmente, mas é a excepção, nunca a regra." },
  { q: "Qual é o método de harmonização de um coral em 4 etapas?", opts: ["1-Melodia 2-Acordes 3-Ritmo 4-Dinâmica", "1-Identificar tonalidade e cadências 2-Colocar o baixo 3-Completar contralto/tenor 4-Verificar as regras", "1-Baixo 2-Soprano 3-Contralto 4-Tenor", "1-Escolher o modo 2-Escrever a melodia 3-Harmonizar 4-Rever"], a: 1, fb: "O método académico em 4 etapas: 1/ Identificar a tonalidade e marcar os pontos cadenciais; 2/ Escrever o baixo (a fundação harmónica); 3/ Completar contralto e tenor evitando erros; 4/ Verificar TODAS as regras (paralelas, dobramentos, sensível, 7ª)." },
  { q: "Em que registo se situa a voz de tenor num coral SATB?", opts: ["Clave de sol, oitava normal", "Clave de sol, soando uma oitava mais baixo (ottava bassa)", "Clave de fá 4ª linha", "Clave de dó 3ª linha"], a: 1, fb: "O tenor é notado em clave de sol com um pequeno '8' por baixo (ottava bassa) — soa uma oitava mais baixo do que está escrito. Na partitura SATB coral, soprano e contralto partilham um pentagrama (hastes para cima/baixo) e tenor+baixo igualmente." },
  { q: "O baixo pode saltar uma quinta num coral Bach?", opts: ["Não — o baixo deve sempre ir por graus conjuntos", "Sim — os saltos de quinta e quarta no baixo são permitidos e frequentes no estilo Bach", "Apenas em cadência", "Apenas se for o primeiro acorde"], a: 1, fb: "Os saltos de quarta e quinta no baixo não só são permitidos como são característicos do estilo Bach — marcam as mudanças harmónicas fortes. Os baixos por movimentos conjuntos são para acordes de passagem; os baixos saltados para as harmonias estruturais." },
  { q: "O que é a 'sensível' na escala de Dó maior?", opts: ["O Dó (tónica)", "O Sol (dominante)", "O Si (sétimo grau natural)", "O Fá (subdominante)"], a: 2, fb: "A sensível é o 7.° grau da escala — Si em Dó maior. Deve o seu nome à sua 'sensibilidade' tonal: está a um semitom da tónica (Si → Dó) e tem portanto uma forte atracção para ela. Não confundir com a subtónica (Sib em Dó maior)." },
  { q: "Como evitar as oitavas paralelas entre soprano e baixo num coral?", opts: ["Mover sempre as vozes na mesma direcção", "Usar movimentos contrários ou oblíquos — se o baixo sobe, o soprano desce (ou fica)", "Saltar sempre em vez de ir por graus", "Dobrar sistematicamente a terça"], a: 1, fb: "O movimento contrário (uma voz sobe, a outra desce) é a melhor forma de evitar oitavas e quintas paralelas. Se o baixo sobe uma quinta, o soprano deve descer. O movimento oblíquo (uma voz estacionária) é também seguro." },
  { q: "O que é um 'coral harmonizado' de Bach?", opts: ["Um coral composto por Bach", "Uma melodia pré-existente (frequentemente luterana) harmonizada a 4 vozes por Bach", "Um coral tocado a órgão solo", "Um coral sem letra"], a: 1, fb: "Bach não compôs as melodias dos seus corais — harmonizou-as. Essas melodias são hinos luteranos pré-existentes (frequentemente do século XVI). Bach produziu ~400 harmonizações SATB dessas melodias, consideradas o cume do género." },
  { q: "Como identificar os 'pontos de respiração' num coral para colocar as cadências?", opts: ["Apenas nas barras de compasso", "Nos pontos, vírgulas e fins de frase do texto — a cadência corresponde à pontuação verbal", "De 4 em 4 compassos", "Apenas no início e no fim"], a: 1, fb: "Num coral, os pontos de respiração seguem o texto cantado. Uma vírgula → cadência de meia ou imperfeita (suspensão). Um ponto → cadência perfeita (final). Bach mapeia rigorosamente a pontuação musical sobre a pontuação verbal — a música respira como a frase." },
  { q: "Que dobramento deve ser absolutamente evitado num acorde de dominante (V)?", opts: ["Dobrar a fundamental", "Dobrar a terça", "Dobrar a sensível", "Dobrar a quinta"], a: 2, fb: "Dobrar a sensível (7.° grau) no acorde de dominante é um erro grave: ambas as sensíveis terão de subir para a tónica, criando oitavas paralelas obrigatórias. Deve-se portanto evitar dobrar a sensível — dobrar a fundamental ou a quinta em vez disso." },
  { q: "Em que contexto Bach permite o movimento de quinta entre baixo e tenor?", opts: ["Nunca", "Nas cadências autênticas plagais", "Quando o movimento é contrário ou oblíquo (quintas directas evitadas)", "Apenas no soprano"], a: 2, fb: "As quintas ocultas (duas vozes atingem uma quinta por movimento directo) devem ser evitadas, especialmente entre as vozes extremas. Porém, uma quinta em movimento contrário (uma sobe, a outra desce) não é paralela. Bach aplica esta regra estritamente às vozes extremas e com flexibilidade às vozes internas." },
  { q: "Como realizar um acorde de dominante a 4 vozes em Dó maior (G7: Sol–Si–Ré–Fá)?", opts: ["Sol–Sol–Si–Ré (dobrar fundamental, omitir 7ª)", "Sol–Si–Ré–Fá (todas as notas, sem dobramento)", "Sol–Si–Sol–Ré (dobrar fundamental, omitir 7ª)", "Sol–Fá–Ré–Si (inversão)"], a: 1, fb: "G7 contém 4 notas distintas (Sol–Si–Ré–Fá), portanto a 4 vozes pode-se escrever todas as notas sem dobramento. Isso é inclusivamente preferível num acorde de dominante pois a sétima (Fá) é crucial para a resolução — não a omitir. Baixo: Sol. Soprano: Sol, Si ou Ré conforme a melodia dada." },
  { q: "O que é o 'sujeito' de uma fuga?", opts: ["O argumento literário do texto", "O tema principal, enunciado a solo no início sobre a tónica, sem acompanhamento", "A resposta harmónica", "O contrasujeito"], a: 1, fb: "O sujeito é o tema principal da fuga — geralmente 1 a 4 compassos. É enunciado a solo no início por uma única voz, sem acompanhamento, sobre a tónica. Tudo o resto da fuga é construído sobre este material inicial." },
  { q: "Qual é a diferença entre 'resposta real' e 'resposta tonal'?", opts: ["A resposta real está na altura certa, a tonal está errada", "A resposta real é uma transposição exacta do sujeito para a dominante; a resposta tonal modifica ligeiramente certos intervalos para evitar uma modulação prematura", "São idênticas", "A resposta tonal é mais longa"], a: 1, fb: "Resposta real: transposição exacta do sujeito para a dominante (quinta acima). Resposta tonal: transposição com modificação de um ou dois intervalos — frequentemente quando o sujeito começa na dominante (quinta), o início da resposta começa na tónica para ancorar a tonalidade." },
  { q: "O que é o 'contrasujeito'?", opts: ["Um segundo sujeito independente", "A melodia que acompanha a resposta simultaneamente — em contraponto com o sujeito ou a resposta, reaparece a cada entrada do sujeito", "O sujeito tocado ao contrário", "O baixo do sujeito"], a: 1, fb: "O contrasujeito é o contraponto escrito para acompanhar a resposta (e o sujeito). Está em contraponto duplo com o sujeito: podem ser invertidos (o sujeito passa para a voz do contrasujeito e vice-versa) sem criar erros. A sua constância é a marca de uma fuga bem construída." },
  { q: "O que se chama 'exposição' numa fuga?", opts: ["A secção de abertura onde todas as vozes entram sucessivamente com o sujeito", "O desenvolvimento central", "A conclusão da fuga", "O primeiro episódio"], a: 0, fb: "A exposição é a secção de abertura da fuga onde todas as vozes entram uma a uma com o sujeito (na tónica) ou a resposta (na dominante). Numa fuga a 4 vozes, a exposição compreende 4 entradas alternando sujeito (I) e resposta (V)." },
  { q: "O que é um 'episódio' numa fuga?", opts: ["Uma secção onde o sujeito está ausente — música de ligação entre duas entradas do sujeito, frequentemente sequencial e modulante", "Outra exposição", "O regresso do sujeito em aumentação", "O contrasujeito a solo"], a: 0, fb: "Um episódio (ou divertimento) é uma secção da fuga onde o sujeito completo não aparece. Ouvem-se frequentemente fragmentos do sujeito ou do contrasujeito em sequências modulantes. Os episódios servem para ligar as entradas do sujeito e modular para outras tonalidades." },
  { q: "O que é o 'stretto'?", opts: ["O sujeito tocado duas vezes seguidas", "A sobreposição de entradas do sujeito — a 2ª voz entra com o sujeito antes de a 1ª voz ter terminado o seu", "O sujeito em aumentação", "A conclusão da fuga"], a: 1, fb: "O stretto é uma técnica de intensificação: as entradas do sujeito sobrepõem-se, criando uma compressão temporal. A 2ª voz começa o sujeito antes de a 1ª o ter terminado. O stretto é frequentemente reservado para o clímax da fuga para criar a máxima tensão." },
  { q: "O que é a 'aumentação' de um sujeito de fuga?", opts: ["Tocar o sujeito mais alto", "Tocar o sujeito em valores duplos — cada semínima torna-se mínima, cada colcheia torna-se semínima", "Transportar o sujeito mais alto", "Tocar o sujeito noutro modo"], a: 1, fb: "A aumentação consiste em tocar o sujeito em valores rítmicos dobrados. Se o sujeito original é: semínima–colcheia–colcheia–semínima, a aumentação dá: mínima–semínima–semínima–mínima. O efeito é engrandecer e solenizar o sujeito, usado frequentemente no clímax final." },
  { q: "O que é a 'inversão' de um sujeito de fuga?", opts: ["Tocar o sujeito ao contrário no tempo", "Inverter o sujeito melodicamente — cada intervalo ascendente torna-se descendente e vice-versa", "Tocar o sujeito no modo oposto", "Tocar o sujeito noutra voz"], a: 1, fb: "A inversão melódica inverte o sujeito: cada intervalo sobe onde descia e vice-versa. Se o sujeito sobe uma terça e depois desce uma segunda, a inversão desce uma terça e depois sobe uma segunda. É uma técnica do contraponto duplo." },
  { q: "Quantas vozes tem geralmente uma fuga de Bach do Cravo Bem Temperado?", opts: ["Sempre 4 vozes", "2 a 5 vozes conforme a fuga, mais frequentemente 3 ou 4", "Sempre 2 vozes", "6 vozes como padrão"], a: 1, fb: "As fugas do Cravo Bem Temperado variam entre 2 e 5 vozes. A maioria é a 3 vozes (flexibilidade pianística) ou 4 vozes (riqueza contrapontística). A fuga a 5 vozes é rara e reservada a momentos de grandiosidade solene. Não há norma fixa — Bach escolhe conforme a expressão pretendida." },
  { q: "O que é o 'Cravo Bem Temperado' de Bach?", opts: ["Um tratado de afinação de pianos", "Uma colectânea de 48 prelúdios e fugas (dois volumes de 24 pares) em todas as 24 tonalidades maiores e menores — obra-prima do contraponto tonal", "Uma ópera em 48 actos", "Um método de piano para principiantes"], a: 1, fb: "O Cravo Bem Temperado (Das Wohltemperierte Klavier) compreende duas colectâneas de 24 prelúdios e fugas cada uma, cobrindo todas as tonalidades maiores e menores. Bach compô-lo para demonstrar a praticabilidade do temperamento igual e para ensinar o contraponto. É a 'bíblia' do pianista clássico." },
  { q: "O que é 'A Arte da Fuga' BWV 1080?", opts: ["Uma ópera de Bach", "O testamento fugal de Bach — 14 fugas (Contrapuncti) e 4 cânones sobre um único sujeito cromático, inacabado à sua morte", "Uma colectânea de 48 corais", "Um concerto para órgão"], a: 1, fb: "A Arte da Fuga é a obra testamento de Bach, composta nos seus últimos anos. Todos os Contrapuncti (fugas) se baseiam no mesmo sujeito: Ré–Lá–Fá–Ré em Dó menor. A obra interrompe-se a meio de uma fuga que introduz o motivo B-A-C-H (Sib–Lá–Dó–Si) — Bach nunca conseguiu terminá-la." },
  { q: "Como identificar o sujeito na exposição de uma fuga à escuta?", opts: ["É sempre a voz mais grave", "É a primeira melodia apresentada a solo sem acompanhamento, em qualquer voz", "É o motivo mais repetido", "É a linha do baixo"], a: 1, fb: "Na exposição, a primeira voz que entra (qualquer que seja a sua tessitura) apresenta o sujeito a solo, sem nenhum acompanhamento. É a única melodia que se ouve. Depois a 2ª voz entra com a resposta (enquanto a 1ª continua com o contrasujeito). Identificar a entrada solitária inicial = identificar o sujeito." },
  { q: "Numa fuga a 4 vozes, qual é a ordem típica das entradas na exposição?", opts: ["Sempre soprano → contralto → tenor → baixo", "Variável — frequentemente agudo→grave ou grave→agudo, alternando tónica e dominante: S-A-T-B ou B-T-A-S", "Sempre as vozes aos pares simultâneos", "Sempre o baixo em primeiro"], a: 1, fb: "A ordem das entradas na exposição varia conforme a fuga. Bach alterna frequentemente entre vozes agudas e graves (S-B-A-T ou B-S-T-A) para criar variedade. A ordem tónica-dominante alterna: voz 1 (sujeito, tónica), voz 2 (resposta, dominante), voz 3 (sujeito, tónica), voz 4 (resposta, dominante)." },
  { q: "O que é a 'codeta' na exposição de uma fuga?", opts: ["A conclusão da fuga", "Uma curta passagem de transição entre as entradas da exposição, permitindo modular brevemente para a dominante antes da entrada da resposta", "O contrasujeito final", "O stretto final"], a: 1, fb: "A codeta é uma breve passagem intersticial na exposição, entre o fim do sujeito e o início da resposta. Permite uma transição harmónica suave (geralmente para a dominante) antes de a 2ª voz entrar. Nem todas as fugas têm codeta — algumas têm entradas directas sem transição." },
  { q: "Como termina geralmente uma fuga?", opts: ["Por uma cadência plagal unicamente", "Por uma cadência perfeita (V→I) com por vezes um pedal de tónica final, frequentemente um acorde com terça picarda no modo menor", "Por uma repetição do sujeito no início", "Por um silêncio"], a: 1, fb: "A fuga termina geralmente com uma forte cadência perfeita (V→I). No modo menor, Bach termina frequentemente com a 'terça picarda' (Dó# em Dó menor → acorde de Dó maior). Um pedal de tónica no baixo pode suportar os últimos compassos, criando estabilidade final após toda a tensão contrapontística." },
  { q: "O que é o 'retrógrado' de um sujeito de fuga?", opts: ["O sujeito tocado com o ritmo invertido", "O sujeito tocado ao contrário — da última nota para a primeira", "O sujeito transposto uma quinta abaixo", "O sujeito fragmentado em motivos curtos"], a: 1, fb: "O retrógrado (ou cancrizans) consiste em tocar o sujeito da última nota para a primeira. Se o sujeito é Dó–Ré–Mib–Fá, o retrógrado é Fá–Mib–Ré–Dó. É uma técnica de contraponto canónico, amplamente usada na Arte da Fuga. Combinado com a inversão, obtém-se o retrógrado invertido." },
  { q: "O que se chama 'contraponto duplo' ou 'contraponto invertível'?", opts: ["Um contraponto com dois sujeitos diferentes", "Um contraponto onde as duas linhas podem ser trocadas (uma passa para a voz grave, a outra para a aguda) sem criar erros de contraponto", "Um contraponto em modo menor", "Um contraponto à oitava"], a: 1, fb: "O contraponto duplo (ou invertível) permite trocar as vozes: a voz superior passa para a posição inferior e vice-versa. Para que isso funcione, os intervalos entre as vozes devem permanecer consonantes em ambas as disposições. Esta é a condição para que um contrasujeito seja 'perfeitamente' construído." },
  { q: "N'\"A Arte da Fuga\", qual é o sujeito que percorre todas as fugas?", opts: ["Sol–Sol–Sol–Mib (como Beethoven)", "Ré–Lá–Fá–Ré em Dó menor (o sujeito unificado de toda a obra)", "Dó–Ré–Mi–Fá (escala ascendente)", "Mi–Fá–Ré–Sol (motivo de 4 notas)"], a: 1, fb: "O sujeito unificado da Arte da Fuga é Ré–Lá–Fá–Ré em Dó menor. Todas as 14 fugas (Contrapuncti) e os 4 cânones são desenvolvimentos contrapontísticos deste mesmo sujeito. A obra demonstra a exaustividade das possibilidades fugais de um único material temático." },
  { q: "O que é um 'cânone' em contraponto, próximo da fuga?", opts: ["Uma peça apenas para instrumentos de sopro em metal", "Uma imitação rigorosa e contínua — a voz 2 segue a voz 1 com exactamente as mesmas notas desfasadas no tempo, indefinidamente", "Um acorde repetido", "Uma sequência cromática"], a: 1, fb: "Um cânone é uma imitação rigorosa e contínua: a voz 2 retoma exactamente o que a voz 1 acabou de tocar (ou à quinta, ou em inversão...). Ao contrário da fuga, a imitação do cânone é total e permanente. Exemplos famosos: Cânone de Pachelbel, Row Your Boat, Frère Jacques em cânone." },
  { q: "Quando se diz que uma fuga usa um 'sujeito tonal' em vez de um 'sujeito real'?", opts: ["Quando o sujeito modula para outra tonalidade", "Quando o sujeito começa na dominante — a resposta começará então na tónica para preservar a centralidade tonal", "Quando o sujeito não tem contrasujeito", "Quando o sujeito é cromático"], a: 1, fb: "Um sujeito que se abre na dominante (Sol em Dó maior) recebe uma 'resposta tonal' em vez de real: a resposta começa na tónica (Dó) em vez da dominante (Ré). Esta modificação mantém Dó como centro e evita que a resposta pareça modular prematuramente para Sol maior." },
];

